INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSG_2017_consolidated', 'VSG', 2017, 'consolidated', 'Công ty không phát sinh giao dịch mua bán, cung cấp dịch vụ hoặc giao dịch khác với các bên liên quan bao gồm thành viên quản lý chủ chốt và cổ đông lớn (Công ty Cổ phần Mua Bán nợ Phương Đông). Không có công nợ với các bên liên quan.', 'Rủi ro nợ vay rất cao. Toàn bộ nợ vay ngắn hạn 392,6 tỷ VND (quy đổi từ USD) đã quá hạn thanh toán do Công ty gặp khó khăn tài chính. Nợ ngắn hạn vượt tài sản ngắn hạn 522,8 tỷ VND. Công ty đang đàm phán với ngân hàng để có kế hoạch trả nợ phù hợp. Lãi suất vay biến động theo thị trường, chủ yếu bằng USD khiến công ty chịu rủi ro tỷ giá.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là nguyên liệu, vật liệu với giá trị không lớn (1,38 tỷ VND) và không có dự phòng giảm giá. Công ty không có bất động sản dở dang hay dự án xây dựng dở dang.', 8, 'Công ty đang trong tình trạng tài chính rất yếu với lỗ lũy kế 469,6 tỷ VND, vốn chủ sở hữu âm 302,4 tỷ VND. Hoạt động kinh doanh cốt lõi (cho thuê tàu) thua lỗ, chỉ có hoạt động cho thuê văn phòng có lợi nhuận. Áp lực nợ vay ngắn hạn rất lớn, toàn bộ đã quá hạn. Công ty phụ thuộc vào sự hỗ trợ của ngân hàng để duy trì hoạt động. Rủi ro về khả năng hoạt động liên tục là rất cao. Điểm rủi ro quản trị cao do tình hình tài chính bi đát và sự phụ thuộc vào nợ vay quá hạn.'),
('VSF_2025_consolidated', 'VSF', 2025, 'consolidated', 'Tổng công ty có giao dịch mua bán hàng với Công ty liên kết Colusa-Miliket với doanh số bán 46.8 tỷ đồng, mua 522 triệu đồng. Các khoản phải thu từ Công ty con Lương thực Hậu Giang (đã phá sản) với tổng giá trị hơn 73 tỷ đồng trả trước và 28 tỷ đồng phải thu khác đã được dự phòng toàn bộ. Các giao dịch này có tính chất thương mại bình thường, không có dấu hiệu bất thường đáng kể.', 'Áp lực nợ vay rất lớn với tổng nợ vay ngắn hạn 2,353 tỷ VND, chiếm tỷ trọng cao trong tổng tài sản. Công ty chủ yếu vay ngắn hạn từ nhiều ngân hàng lớn (BIDV, Vietcombank, MSB, MB Bank) với hạn mức tín dụng không tài sản đảm bảo. Tỷ lệ nợ vay/VCSH ở mức cao (~96%). Nợ dài hạn chỉ có 3.4 tỷ VND từ BIDV. Rủi ro thanh toán ngắn hạn đáng lo ngại do phụ thuộc lớn vào tín dụng ngân hàng để tài trợ vốn lưu động cho hoạt động kinh doanh gạo có tính mùa vụ.', 'Hàng tồn kho có giá trị ghi sổ lớn (1,508 tỷ VND), trong đó hàng hóa bất động sản chiếm tỷ trọng đáng kể (883 tỷ VND). Khoản hàng hóa bất động sản tại KCN Nhơn Hòa (703 tỷ) đang bị phong tỏa phục vụ điều tra xét xử vụ án, giá trị thu hồi không chắc chắn. Dự án Kho Khánh Hưng đang tạm dừng. Hàng tồn kho thiếu tại Công ty Lương thực Trà Vinh (649 tỷ) đã dự phòng toàn bộ. Công ty có rủi ro tồn kho dở dang và bất động sản đầu tư không sinh lời.', 7, 'Tổng công ty Lương thực Miền Nam (VSF) là doanh nghiệp nhà nước cổ phần hóa, hoạt động chính trong lĩnh vực kinh doanh xuất khẩu gạo. Năm 2025, doanh thu giảm 17% so với cùng kỳ nhưng lợi nhuận sau thuế tăng hơn 100% (62 tỷ đồng so với 30 tỷ đồng). Điểm tích cực là dòng tiền hoạt động kinh doanh dương mạnh (492 tỷ), cải thiện từ mức âm 598 tỷ năm trước. Tuy nhiên, doanh nghiệp đối mặt với nhiều rủi ro: (1) Quyết toán cổ phần hóa chưa hoàn tất có thể thay đổi giá trị tài sản; (2) Nợ vay ngắn hạn rất lớn với áp lực trả nợ liên tục; (3) Hàng tồn kho bất động sản bị phong tỏa và nhiều khoản phải thu khó đòi; (4) Công ty con Lương thực Hậu Giang đã phá sản. Triển vọng trung bình, phù hợp cho nhà đầu tư thận trọng.'),
('VSG_2016_consolidated', 'VSG', 2016, 'consolidated', 'Công ty không phát sinh giao dịch với các bên liên quan, rủi ro liên quan là thấp.', 'Công ty có nợ vay quá hạn lớn với ngân hàng, lỗ lũy kế, và nợ ngắn hạn vượt quá tài sản ngắn hạn, cho thấy rủi ro thanh khoản rất cao và nguy cơ phá sản.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu với giá trị tương đối nhỏ, không có dự phòng giảm giá, rủi ro tồn kho thấp.', 7, 'Công ty đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, nợ ngắn hạn vượt quá tài sản ngắn hạn, và khả năng hoạt động liên tục phụ thuộc vào sự hỗ trợ của ngân hàng. Doanh thu từ hoạt động cho thuê tàu giảm, trong khi chi phí lãi vay cao. Triển vọng đầu tư tiêu cực.'),
('VSG_2015_consolidated', 'VSG', 2015, 'consolidated', 'Không phát sinh giao dịch với các bên liên quan. Không có rủi ro giao dịch bất thường.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 508.996.977.891 VND. Lỗ lũy kế 379.087.967.353 VND. Công ty gặp khó khăn về luồng tiền, nợ vay quá hạn chưa thanh toán.', 'Hàng tồn kho nguyên liệu, vật liệu giá trị thấp, không có dự phòng giảm giá, rủi ro thấp.', 7, 'Tình hình tài chính nghiêm trọng: lỗ lũy kế lớn, nợ ngắn hạn vượt quá tài sản ngắn hạn, nghi ngờ khả năng hoạt động liên tục. Ban lãnh đạo đang đàm phán ngân hàng để tái cơ cấu nợ. Triển vọng đầu tư tiêu cực.'),
('VSF_2023_consolidated', 'VSF', 2023, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là bán hàng và chia cổ tức với Công ty liên kết Colusa-Miliket, không có dấu hiệu bất thường lớn. Tuy nhiên, số dư phải thu và trả trước với Công ty con Công ty Cổ phần Lương thực Hậu Giang (đã phá sản) có thể là rủi ro tiềm ẩn do khả năng thu hồi thấp.', 'Nợ vay chủ yếu là ngắn hạn từ các ngân hàng thương mại lớn, lãi suất theo thỏa thuận và có tài sản thế chấp. Công ty có tỷ lệ nợ ngắn hạn cao so với vốn chủ sở hữu, nhưng doanh thu từ hoạt động kinh doanh gạo và lương thực đủ để duy trì thanh khoản. Áp lực nợ vay có thể tăng nếu thị trường suy thoái.', 'Hàng tồn kho bao gồm nguyên vật liệu và thành phẩm nông sản, có dự phòng giảm giá. Dự án xây dựng dở dang có một số dự án tạm ngừng thi công (như Dự án Kho trung tâm Khánh Hưng), có nguy cơ chậm tiến độ và tăng chi phí.', 6, 'Tổng Công ty Lương thực Miền Nam - CTCP có tình hình tài chính cải thiện trong năm 2023 với lợi nhuận sau thuế tăng mạnh. Tuy nhiên, còn tồn tại rủi ro từ quyết toán cổ phần hóa chưa được phê duyệt, nợ vay ngắn hạn lớn và một số dự án đầu tư dở dang. Triển vọng đầu tư phụ thuộc vào diễn biến thị trường nông sản quốc tế, khả năng giải quyết các vấn đề pháp lý và quản trị rủi ro.'),
('VSF_2024_consolidated', 'VSF', 2024, 'consolidated', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan rộng với 12 công ty con và 4 công ty liên kết. Tổng doanh thu bán hàng với các bên liên quan đạt ~98 tỷ đồng (0,87% doanh thu thuần), tổng mua hàng đạt ~270 tỷ đồng (2,5% giá vốn). Đáng chú ý, nhiều khoản phải thu từ công ty con (Tô Châu 88,3 tỷ, Lương thực TP.HCM 24,4 tỷ, Lương thực Hậu Giang 17,3 tỷ và 28 tỷ bảo lãnh) đã được trích lập dự phòng 100% do quá hạn trên 5 năm. Khoản trả trước cho Công ty CP Lương thực Hậu Giang (đã phá sản) 73,2 tỷ cũng đã dự phòng toàn bộ. Các giao dịch mua bán với công ty con không có dấu hiệu bất thường về giá, nhưng rủi ro lớn nhất là khả năng thu hồi nợ từ các công ty con hoạt động yếu kém hoặc đã phá sản.', 'Áp lực nợ vay rất lớn với tổng nợ ngắn hạn 916,3 tỷ VNĐ và nợ dài hạn chỉ 0,9 tỷ VNĐ. Dư nợ vay tập trung ở 9 tổ chức tín dụng lớn (MB, Vietcombank, HDBank, MSB, BIDV, SHB, Public Bank, SeABank). Hầu hết các khoản vay không yêu cầu tài sản bảo đảm, dựa trên hạn mức tín dụng không có đảm bảo - cho thấy ngân hàng đánh giá tín nhiệm tốt dựa trên hoạt động kinh doanh gạo. Chi phí lãi vay năm 2024 là 119,2 tỷ VNĐ. Công ty đang lỗ lũy kế 2.641,5 tỷ VNĐ và dòng tiền kinh doanh âm 235,6 tỷ VNĐ, phụ thuộc lớn vào việc duy trì hạn mức tín dụng ngân hàng để đảo nợ.', 'Tồn kho tăng mạnh 38% từ đầu năm (609,4 tỷ lên 843,3 tỷ), đặc biệt thành phẩm tăng 122% (từ 198,8 tỷ lên 441,6 tỷ) phản ánh tích lũy hàng xuất khẩu. Hàng hóa bất động sản 46,3 tỷ đang bị phong tỏa do tranh chấp pháp lý. Dự án kho Khánh Hưng 5,5 tỷ bị tạm dừng nhiều năm, rủi ro ứ đọng vốn. Tài sản thiếu chờ xử lý 649 tỷ (gạo thiếu tại Trà Vinh) đã được dự phòng toàn bộ nhưng vẫn chiếm tỷ trọng lớn trên bảng cân đối, khả năng thu hồi từ thi hành án thấp.', 7, 'Tổng Công ty Lương thực Miền Nam (VSF) là doanh nghiệp nhà nước cổ phần hóa, hoạt động chính trong lĩnh vực kinh doanh và xuất khẩu gạo. Doanh thu thuần 11.300 tỷ VNĐ (giảm 9,9% so với năm trước), lợi nhuận sau thuế chỉ 4,3 tỷ VNĐ, biên lợi nhuận gộp ~5,9% - biên mỏng đặc trưng của ngành thương mại gạo. Điểm yếu lớn nhất là lỗ lũy kế khổng lồ 2.641,5 tỷ VNĐ (gấp 516 lần lợi nhuận năm), dòng tiền kinh doanh âm 235,6 tỷ. Công ty phụ thuộc hoàn toàn vào tín dụng ngân hàng (916 tỷ nợ ngắn hạn) với phần lớn không có tài sản bảo đảm. Nhiều khoản đầu tư vào công ty con đã trích lập dự phòng giảm giá lớn (454 tỷ trên tổng đầu tư 1.181 tỷ). Mặt tích cực: Doanh thu vẫn ổn định, công ty được hưởng hạn mức tín dụng lớn từ nhiều ngân hàng uy tín, và đang triển khai đề án tái cơ cấu. Tuy nhiên, rủi ro quản trị ở mức cao do nợ xấu nội bộ lớn, tài sản thiếu chờ xử lý, và cơ chế quyết toán cổ phần hóa chưa hoàn tất.'),
('VSF_2023_parent', 'VSF', 2023, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con, bao gồm bán hàng, mua hàng, và cho vay. Một số khoản phải thu từ công ty con đã trích lập dự phòng toàn bộ (ví dụ: Công ty TNHH Xuất nhập khẩu Thương mại Võ Thị Thu Hà 58.768 triệu, Công ty Cổ phần Tô Châu 25.865 triệu), cho thấy rủi ro thu hồi nợ từ bên liên quan cao. Tuy nhiên, không có bằng chứng giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay cao với tổng nợ vay khoảng 812.791 triệu VND, trong đó nợ ngắn hạn chiếm tỷ trọng lớn. Doanh nghiệp đang chịu lỗ lũy kế 2.645.851 triệu VND, thâm hụt vốn chủ sở hữu, và dòng tiền hoạt động kinh doanh âm trong năm 2023. Khả năng thanh toán phụ thuộc vào việc duy trì hạn mức tín dụng. Tài sản thế chấp gồm bất động sản và quyền sử dụng đất.', 'Hàng tồn kho có giá trị cao (618.441 triệu VND), trong đó hàng hóa bất động sản 46.272 triệu VND đang bị phong tỏa liên quan đến vụ án. Tài sản thiếu chờ xử lý 659.331 triệu VND đã trích lập dự phòng toàn bộ, phát sinh từ vụ tham ô tại Công ty Lương thực Trà Vinh. Điều này cho thấy rủi ro tồn kho và khả năng thu hồi tài sản thấp.', 7, 'Doanh nghiệp đang trong giai đoạn khó khăn với lỗ lũy kế lớn, dòng tiền hoạt động kinh doanh âm, và phụ thuộc vào tín dụng ngân hàng. Tuy nhiên, doanh thu thuần tăng 24.7% và lợi nhuận sau thuế tăng 53.7% so với cùng kỳ. Công ty đang thực hiện đề án tái cơ cấu. Triển vọng đầu tư phụ thuộc vào khả năng thực hiện tái cơ cấu, thu hồi nợ từ bên liên quan, và xử lý các khoản tồn đọng.'),
('VSF_2022_consolidated', 'VSF', 2022, 'consolidated', 'Rủi ro cao: Tổng Công ty có giao dịch lớn với Công ty CP Lương thực Hậu Giang - công ty con đã phá sản từ năm 2014 theo Quyết định 01/2020/QĐ-PS ngày 22/9/2020, nhưng vẫn ghi nhận khoản đầu tư 28,77 tỷ VND (đã dự phòng toàn bộ), trả trước cho người bán 73,23 tỷ (đã dự phòng toàn bộ), phải thu khách hàng 54,39 tỷ (đã dự phòng toàn bộ), người mua trả tiền trước 9,5 tỷ. Tổng nợ xấu từ công ty con này khoảng 165,9 tỷ VND. Kiểm toán viên không thể thu thập bằng chứng kiểm toán đầy đủ về công ty con này, dẫn đến ý kiến kiểm toán ngoại trừ. Công ty CP Xây lắp Cơ khí và Lương thực Thực phẩm (công ty con) đang thế chấp tài sản cố định tại Agribank chi nhánh Cà Mau cho khoản vay 83,7 tỷ.', 'Áp lực nợ vay cao: Tổng nợ ngắn hạn 2.553 tỷ VND và nợ dài hạn 7,22 tỷ VND. Nợ ngắn hạn tăng mạnh từ 1.899 tỷ lên 2.553 tỷ trong năm, cho thấy hoạt động kinh doanh dựa nhiều vào vốn vay. Chi phí lãi vay năm 2022 là 128,5 tỷ VND. Công ty vay từ nhiều ngân hàng lớn (VCB, MB, HDBank, MSB, BIDV, VPBank, VietinBank, Eximbank, Agribank, PVComBank, Public Bank) với hạn mức tín dụng rất lớn. Nhiều khoản vay được đảm bảo bằng tài sản cố định (nhà kho, nhà xưởng, QSDĐ) hoặc hàng tồn kho luân chuyển, một số khoản tín chấp. Có khoản vay cá nhân lãi suất 10,5%/năm. Tỷ lệ nợ vay/vốn chủ sở hữu khoảng 1.04 cho thấy đòn bẩy tài chính ở mức cao.', 'Rủi ro tồn kho đáng kể: Hàng tồn kho thiếu chờ xử lý trị giá 671,25 tỷ VND (bao gồm 661,98 tỷ từ vụ án tại Công ty Lương thực Trà Vinh và 6,5 tỷ tài sản khác), đã dự phòng toàn bộ. Hàng hóa bất động sản tại KCN Nhơn Hòa, Bình Định bị phong tỏa phục vụ điều tra. Dự án Kho Khánh Hưng tạm dừng chưa biết thời gian tiếp tục. Dự án nhà máy chế biến nông sản xuất khẩu tạm ngừng từ 2015. Hàng tồn kho giảm từ 1.417 tỷ xuống 1.172 tỷ nhưng dự phòng giảm giá giảm mạnh từ 108 tỷ xuống 26,8 tỷ, cần theo dõi chất lượng tồn kho. Khu đất dự án Hoàng Hải đang tiến hành thủ tục sang nhượng.', 7, 'Tổng Công ty Lương thực miền Nam - CTCP (VSF) là doanh nghiệp nhà nước cổ phần hóa với vốn điều lệ 5.000 tỷ đồng, hoạt động chính trong lĩnh vực bán buôn gạo và nông sản. Năm 2022 doanh thu thuần đạt 17.304 tỷ, LNST đạt 21,1 tỷ (đảo chiều từ lỗ 324 tỷ năm 2021). Tuy nhiên, tình hình tài chính còn nhiều rủi ro: (1) Ý kiến kiểm toán ngoại trừ do không kiểm soát được công ty con đã phá sản; (2) Quyết toán cổ phần hóa chưa hoàn tất, tài sản đất đai tạm ghi có thể thay đổi; (3) Nợ xấu lớn từ các bên liên quan và đối tác; (4) Hàng tồn kho thiếu chờ xử lý 671 tỷ; (5) Đòn bẩy tài chính cao; (6) Nhiều dự án xây dựng dở dang tạm dừng. Công ty có triển vọng cải thiện doanh thu xuất khẩu nhưng cần xử lý dứt điểm các tồn đọng về cổ phần hóa, nợ xấu và tài sản thiếu.'),
('VSF_2022_parent', 'VSF', 2022, 'parent', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm bán hàng, mua hàng và cổ tức. Một số khoản phải thu và trả trước cho người bán liên quan đã được dự phòng, cho thấy rủi ro tín dụng. Tuy nhiên, không có bằng chứng giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay cao với nợ ngắn hạn 1.691.611.976.423 VND và nợ dài hạn 4.449.700.000 VND. Khả năng thanh toán phụ thuộc vào hạn mức tín dụng từ ngân hàng. Tài sản thế chấp chủ yếu là tín chấp, một số khoản vay có thế chấp tài sản cố định.', 'Hàng tồn kho có dự phòng giảm giá, và một phần tài sản thiếu chờ xử lý liên quan đến vụ án điều tra. Dự án xây dựng dở dang có thể bị ứ đọng, nhưng tổng giá trị không quá lớn.', 7, 'Tổng Công ty đã chuyển từ lỗ sang lãi năm 2022 sau ảnh hưởng của COVID-19. Tuy nhiên, công ty vẫn có lỗ lũy kế lớn và thâm hụt vốn chủ sở hữu. Tình hình tài chính phụ thuộc vào ngân hàng và cần cải thiện quản lý nợ và tài sản. Triển vọng đầu tư trung bình do rủi ro nợ và tài sản cố định.'),
('VTM_2018_consolidated', 'VTM', 2018, 'consolidated', 'Văn bản là hợp đồng kiểm toán, không chứa báo cáo tài chính hay thuyết minh chi tiết về giao dịch với các bên liên quan. Không đủ dữ liệu để đánh giá rủi ro cụ thể.', 'Văn bản là hợp đồng kiểm toán, không chứa thuyết minh nợ vay chi tiết. Không đủ dữ liệu để đánh giá áp lực nợ vay.', 'Văn bản là hợp đồng kiểm toán, không chứa thuyết minh hàng tồn kho và dự án xây dựng dở dang. Không đủ dữ liệu để đánh giá rủi ro tồn kho.', 5, 'Tài liệu cung cấp là hợp đồng dịch vụ kiểm toán và soát xét, không phải báo cáo tài chính đã kiểm toán. Do đó, không có đủ dữ liệu tài chính định lượng để phân tích sức khỏe tài chính, thanh khoản hay triển vọng đầu tư của doanh nghiệp. Việc đánh giá cần dựa trên các báo cáo tài chính chính thức (Bảng cân đối kế toán, Báo cáo kết quả hoạt động kinh doanh, Báo cáo lưu chuyển tiền tệ và Thuyết minh BCTC) được phát hành sau khi cuộc kiểm toán do PKF Việt Nam thực hiện hoàn thành.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('WSB_2015_parent', 'WSB', 2015, 'parent', 'Doanh nghiệp có giao dịch lớn và thường xuyên với các bên liên quan, đặc biệt là công ty mẹ và công ty con, tập trung vào mua bán hàng hóa và dịch vụ. Có khoản phải thu hỗ trợ thuế TTĐB từ công ty mẹ (74.68 tỷ VNĐ) và khoản phải thu lợi nhuận từ công ty con (66.01 tỷ VNĐ). Rủi ro về chuyển giá và thanh toán cần được giám sát.', 'Tổng nợ vay (ngắn và dài hạn) khoảng 183.63 tỷ VNĐ, với lãi suất biến động theo thị trường. Công ty đã chuyển 43 tỷ nợ dài hạn đáo hạn sang nợ ngắn hạn. Tài sản thế chấp cho khoản vay dài hạn là các TSCĐ hình thành từ dự án. Áp lực trả nợ gốc và lãi vay tăng trong ngắn hạn.', 'Giá trị hàng tồn kho giảm mạnh từ 50.23 tỷ (2014) xuống 31.79 tỷ (2015), cho thấy có thể hàng hóa lưu thông chậm hoặc đã được bán. Chi phí xây dựng dở dang giảm mạnh do dự án đã hoàn thành và chuyển giao sang TSCĐ. Rủi ro tồn kho thấp do không trích lập dự phòng.', 6, 'Công ty ghi nhận lợi nhuận tăng trưởng mạnh năm 2015, chủ yếu do doanh thu tài chính từ lợi nhuận chuyển về của công ty con. Tuy nhiên, kết quả kinh doanh bị ảnh hưởng bởi khoản tranh chấp thuế TTĐB. Công ty thực hiện tái cấu trúc bằng việc đóng cửa nhà máy Sóc Trăng và đã hoàn thành dự án đầu tư chính. Rủi ro chính đến từ giao dịch với các bên liên quan và áp lực tài chính ngắn hạn tăng do cơ cấu nợ thay đổi.'),
('XPH_2016_consolidated', 'XPH', 2016, 'consolidated', 'Công ty có giao dịch mua bán với các bên liên quan trong tập đoàn, tuy nhiên không có thông tin về lãi suất hoặc điều kiện bất thường, nhưng cần theo dõi để đảm bảo giá thị trường.', 'Công ty không có nợ vay tài chính, do đó áp lực nợ là không có.', 'Hàng tồn kho không có dự phòng, các dự án xây dựng dở dang có thể bị ứ đọng nếu không triển khai đúng tiến độ.', 4, 'Công ty có tình hình tài chính ổn định với lợi nhuận nhỏ trong năm 2016 sau lỗ năm trước. Không có nợ vay, nhưng dòng tiền hoạt động đầu tư âm do đầu tư vào tiền gửi có kỳ hạn. Triển vọng trung bình.'),
('VTJ_2021_parent', 'VTJ', 2021, 'parent', 'Công ty có các khoản đầu tư vào công ty con và công ty liên kết với giá trị lớn và dự phòng giảm giá đáng kể, nhưng không có giao dịch mua bán với các bên liên quan trong năm 2021.', 'Nợ ngắn hạn chiếm tỷ trọng cao với khoản vay 10 tỷ VNĐ và các khoản phải trả khác, trong khi tiền và tương đương tiền giảm mạnh, tạo áp lực thanh khoản.', 'Hàng tồn kho không có, chỉ có chi phí xây dựng cơ bản dở dang cho dự án Văn phòng Vinataba, không có rủi ro tồn kho.', 5, 'Công ty có lợi nhuận trong năm 2021 nhưng nợ vay cao, thanh khoản giảm, và các khoản đầu tư có dự phòng lớn. Triển vọng phụ thuộc vào hiệu quả của các khoản đầu tư và quản lý nợ.'),
('VTD_2024_consolidated', 'VTD', 2024, 'consolidated', 'Tập đoàn có mối quan hệ phức tạp với nhiều bên liên quan: thoái vốn toàn bộ 45% cổ phần tại Công ty Cổ phần Lữ hành Vietourist và 21,52% cổ phần tại Công ty Cổ phần Tập đoàn Hoàng Kim Tây Nguyên trong năm 2024. Giao dịch thoái vốn lớn (tổng cộng hơn 42.5 tỷ VNĐ) với công ty liên kết. Tiền gửi cho vay cá nhân (ông Nguyễn Bá Trang) 5 tỷ VNĐ lãi suất 6%/năm, và phải thu bán cổ phần từ cá nhân (ông Mai Văn Thống 17.2 tỷ, bà Nguyễn Nữ Huệ Phương 20.1 tỷ). Các giao dịch này cần được giám sát chặt chẽ về tính minh bạch.', 'Áp lực nợ vay rất lớn với tổng nợ vay 84.5 tỷ VNĐ (nợ ngắn hạn 48.7 tỷ + nợ dài hạn 10.9 tỷ + nợ dài hạn đến hạn trả 5.9 tỷ), tăng mạnh so với năm trước (72.2 tỷ). Tiền mặt chỉ 13 tỷ VNĐ, tỷ lệ nợ vay/vốn chủ sở hữu cao (~59%). Nợ vay chủ yếu phục vụ bổ sung vốn lưu động và mua phương tiện vận tải. Phần lớn lãi suất theo thời điểm nhận nợ, rủi ro lãi suất biến động. Tài sản đảm bảo chủ yếu là phương tiện vận tải và tiền gửi có kỳ hạn.', 'Hàng tồn kho 6.27 tỷ VNĐ chủ yếu là chi phí sản xuất kinh doanh dở dang (6.19 tỷ), liên quan đến khoản đặt cọc mua bất động sản tại dự án Regal Legend Quảng Bình. Rủi ro ứ đọng nếu dự án bất động sản không triển khai đúng tiến độ. Hàng hóa tồn kho chỉ 86.8 triệu VNĐ, mức thấp và không đáng lo ngại. Không trích lập dự phòng giảm giá hàng tồn kho.', 4, 'Tình hình tài chính Vietourist Holdings trong năm 2024 suy giảm nghiêm trọng: lỗ ròng 5.4 tỷ VNĐ (năm trước lãi 670 triệu), biên lợi nhuận gộp giảm từ 13.7% xuống 10.2%, dòng tiền hoạt động kinh doanh âm 29.9 tỷ VNĐ. Công ty thoái vốn khỏi nhiều công ty liên kết trong năm, cho thấy quá trình tái cơ cấu. Nợ vay tăng mạnh trong khi doanh thu chỉ tăng nhẹ 8%. Công ty chịu phạt vi phạm hợp đồng 1.82 tỷ VNĐ. Dòng tiền hoạt động kinh doanh âm liên tục 2 năm (2023 và 2024) cho thấy áp lực thanh toán nợ rất lớn. Triển vọng đầu tư tiêu cực, cần theo dõi khả năng phục hồi hoạt động kinh doanh và tái cơ cấu nợ.'),
('VSI_2022_parent', 'VSI', 2022, 'parent', 'Công ty có giao dịch thường xuyên với các bên liên quan bao gồm công ty mẹ (Viwaseen), công ty con và công ty cùng công ty mẹ. Các giao dịch chủ yếu mang tính thương mại như cho thuê văn phòng, bán vật tư xây dựng (thép), hợp đồng thi công xây dựng liên danh. Có khoản phải thu từ Công ty CP XD TM An Xuân Thịnh trị giá 8.988.910.834 đồng đã quá hạn trên 3 năm, đang trong quá trình tranh chấp tòa án (giám đốc thẩm), tiềm ẩn rủi ro thu hồi. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn bất hợp lý với các bên liên quan.', 'Tổng nợ vay khoảng 49,57 tỷ VNĐ (ngắn hạn 10,76 tỷ, dài hạn 38,82 tỷ) so với vốn chủ sở hữu 201,34 tỷ - tỷ lệ nợ vay/vốn chủ sở hữu khoảng 24,6%, mức đòn bẩy an toàn. Nợ dài hạn 38,82 tỷ có lãi suất 12%/năm với kỳ hạn 138 tháng, được đảm bảo bằng bất động sản đầu tư trị giá 128,3 tỷ (giá trị sổ sách). Dòng tiền thuần từ hoạt động kinh doanh đạt 51,17 tỷ, đủ khả năng chi trả lãi vay (7,26 tỷ) và trả nợ gốc. Tuy nhiên, tỷ lệ chi phí lãi vay/doanh thu thuần khoảng 2,4% cho thấy áp lực lãi vay ở mức kiểm soát được.', 'Tổng hàng tồn kho 11,85 tỷ (sau dự phòng 376 triệu) chiếm tỷ trọng nhỏ trong tổng tài sản. Dự phòng giảm giá hàng tồn kho không thay đổi so với năm trước (376 triệu). Chi phí xây dựng cơ bản dở dang 13,42 tỷ bao gồm dự án khu phức hợp Quận 9 (11,4 tỷ) và các khoản sửa chữa, đầu tư khác. Các dự án dở dang tăng so với đầu năm (từ 10,95 tỷ lên 13,42 tỷ), cho thấy công ty đang triển khai đầu tư xây dựng, chưa có dấu hiệu ứ đọng nghiêm trọng.', 4, 'WASECO là doanh nghiệp xây dựng cấp thoát nước có vốn điều lệ 132 tỷ, hoạt động ổn định với doanh thu thuần 304,5 tỷ và lợi nhuận sau thuế 25 tỷ năm 2022. Biên lợi nhuận gộp khoảng 18,2%. Công ty có cơ cấu tài sản lành mạnh với bất động sản đầu tư 128,3 tỷ tạo nguồn thu cho thuê, dòng tiền kinh doanh dương mạnh (51,17 tỷ). Nợ vay ở mức kiểm soát được với tài sản đảm bảo充足. Tuy nhiên, công ty có khoản phải thu quá hạn lớn (>3 năm) từ Công ty An Xuân Thịnh đang tranh chấp pháp lý, và tỷ suất lợi nhuận giảm so với năm trước (lợi nhuận sau thuế giảm từ 30,7 tỷ xuống 25 tỷ). Công ty con (Mêkông Rạch Giá) có dự phòng tổn thất đầu tư tăng từ 18,2 tỷ lên 20 tỷ, phản ánh tình hình hoạt động chưa khả quan.'),
('VSM_2022_parent', 'VSM', 2022, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ và công ty con, chủ yếu là vay/cho vay và mua bán hàng hóa dịch vụ. Các khoản vay có lãi suất dựa trên lãi suất tiết kiệm, có vẻ minh bạch. Tuy nhiên, sự phụ thuộc vào vốn từ công ty mẹ và giao dịch nội bộ có thể tạo rủi ro nếu không được giám sát chặt chẽ.', 'Nợ vay chủ yếu đến từ công ty mẹ với kỳ hạn dài, áp lực trả nợ tập trung vào nợ ngắn hạn. Công ty có dòng tiền từ hoạt động kinh doanh và tài sản tài chính, nhưng cần theo dõi khả năng thanh toán và biến động lãi suất.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu với giá trị thấp và không có dự phòng giảm giá, rủi ro tồn kho thấp.', 4, 'Công ty có doanh thu và lợi nhuận tăng trưởng tốt trong năm 2022. Cơ cấu tài chính ổn định với vốn chủ sở hữu tăng, nhưng nợ vay cũng tăng đáng kể. Khả năng sinh lời cải thiện, nhưng cần quản lý rủi ro từ giao dịch bên liên quan và nợ vay. Triển vọng đầu tư trung bình khá, phù hợp với nhà đầu tư chấp nhận rủi ro trung bình.'),
('VSF_2020_consolidated', 'VSF', 2020, 'consolidated', 'Có giao dịch với bên liên quan như cho vay, mua hàng, và thanh toán cho ban lãnh đạo. Một số khoản phải thu từ bên liên quan đã trích lập dự phòng 100%, cho thấy rủi ro thu hồi cao.', 'Áp lực nợ vay lớn với tổng nợ phải trả 3.893 tỷ VND, vượt vốn chủ sở hữu 2.870 tỷ VND. Công ty liên tục lỗ, ảnh hưởng đến khả năng thanh toán nợ. Tài sản thế chấp gồm tài sản cố định hữu hình với giá trị 298 tỷ VND.', 'Tồn kho có dự phòng giảm giá đáng kể, đặc biệt hàng hoá với dự phòng 46.6 tỷ VND trên giá trị 513.9 tỷ VND, cho thấy rủi ro giảm giá hoặc tồn đọng. Dự án xây dựng dở dang có thể bị trì hoãn.', 6, 'Tổng Công ty Lương thực Miền Nam đang trong tình trạng tài chính khó khăn với lỗ liên tiếp, nợ cao, và tồn kho rủi ro. Triển vọng phụ thuộc vào sự phục hồi của thị trường xuất khẩu gạo và quản lý nợ hiệu quả. Cần cải thiện quản trị và cơ cấu tài chính.'),
('VSF_2019_consolidated', 'VSF', 2019, 'consolidated', 'Doanh nghiệp có các giao dịch với công ty con Công ty Cổ phần Lương thực Hậu Giang đã ngừng hoạt động từ 2014, bao gồm khoản phải thu thương mại 54,39 tỷ VND và trả trước cho người bán 80,75 tỷ VND. Các khoản này đã được dự phòng toàn bộ. Có rủi ro mất vốn do công ty con đang trong quá trình phá sản.', 'Doanh nghiệp có nợ vay ngắn hạn 2,206 tỷ VND và dài hạn 11,96 tỷ VND, tổng nợ vay chiếm tỷ trọng lớn trong tổng tài sản. Nợ ngắn hạn vượt quá tài sản ngắn hạn 55,69 tỷ VND, tạo áp lực thanh toán. Nhiều khoản vay được đảm bảo bằng tài sản cố định, có rủi ro bị phát mãi nếu không trả được nợ.', 'Hàng tồn kho thiếu chờ xử lý tại Công ty Lương thực Trà Vinh với giá trị 662 tỷ VND đã dự phòng toàn bộ, đang được cơ quan điều tra. Dự án xây dựng cơ bản dở dang có thể chậm tiến độ (dự án Kho Khánh Hưng tạm dừng). Hàng hóa bất động sản có thể khó thanh khoản.', 7, 'Tổng Công ty Lương thực Miền Nam có tình hình tài chính yếu kém với lỗ lũy kế lớn (2,181 tỷ VND), nợ vay cao, hàng tồn kho thiếu chờ xử lý và nhiều khoản đầu tư vào công ty con/liên kết hoạt động kém. Quyết toán cổ phần hóa chưa hoàn tất tạo不确定性. Doanh nghiệp có nguy cơ về giả định hoạt động liên tục nếu không tái cơ cấu nợ và cải thiện kinh doanh.'),
('VSF_2020_parent', 'VSF', 2020, 'parent', 'Có nhiều giao dịch với bên liên quan, đặc biệt là các công ty con, với các khoản phải thu lớn đã quá hạn và phải trích lập dự phòng. Điều này cho thấy rủi ro về khả năng thu hồi và quản trị doanh nghiệp.', 'Nợ ngắn hạn vượt tài sản ngắn hạn, công ty có lỗ lũy kế lớn và cần tái tài trợ các khoản vay. Áp lực nợ vay cao, tài sản thế chấp chủ yếu là tài sản cố định.', 'Hàng tồn kho có dự phòng giảm giá, và có tài sản thiếu chờ xử lý từ năm 2017. Dự án xây dựng dở dang có thể bị ứ đọng do tạm dừng.', 8, 'Tổng Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn, nợ vượt tài sản, và nhiều rủi ro liên quan đến bên liên quan và tồn kho. Cần theo dõi khả năng tái cơ cấu nợ và hoạt động liên tục.'),
('VSF_2019_parent', 'VSF', 2019, 'parent', 'Giao dịch với các bên liên quan chủ yếu là bán hàng và mua hàng hóa với giá trị lớn, không có thông tin về lãi suất hoặc điều kiện bất thường. Tuy nhiên, số dư phải thu và trả trước với các công ty con là đáng kể, cần theo dõi khả năng thu hồi.', 'Áp lực nợ vay cao với nợ ngắn hạn 1.316 tỷ VNĐ và nợ dài hạn 8,1 tỷ VNĐ. Phần lớn vay ngắn hạn không được đảm bảo, dựa vào hạn mức tín dụng. Tài sản cố định thế chấp cho một số khoản vay dài hạn, nhưng rủi ro tái tài trợ vẫn lớn do nợ ngắn hạn vượt quá tài sản ngắn hạn.', 'Hàng tồn kho giảm mạnh từ 1.946 tỷ VNĐ xuống 727 tỷ VNĐ, có dự phòng giảm giá 4,7 tỷ VNĐ. Hàng hóa bất động sản và dự án Kho Khánh Hưng có thể bị ứ đọng hoặc chậm tiến độ, ảnh hưởng đến dòng tiền.', 7, 'Tổng Công ty lỗ nặng 192,6 tỷ VNĐ trong năm 2019 do cạnh tranh gay gắt và giá gạo thấp. Nợ vay cao, vốn chủ sở hữu bị xói mòn bởi lỗ lũy kế 2.027 tỷ VNĐ. Dù ban lãnh đạo cam kết hoạt động liên tục, rủi ro tài chính và quản trị vẫn lớn, cần theo dõi quyết toán cổ phần hóa và tái cơ cấu nợ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSF_2021_parent', 'VSF', 2021, 'parent', 'Công ty có giao dịch lớn với các công ty con và liên kết, bao gồm bán hàng, mua hàng và chia cổ tức. Một số khoản phải thu và trả trước cho các bên liên quan (như Công ty Cổ phần Tô Châu, Công ty Cổ phần Lương thực Hậu Giang) đã quá hạn trên 5 năm và được dự phòng toàn bộ, cho thấy rủi ro thu hồi cao. Các giao dịch này không có bảo đảm và không tính lãi.', 'Nợ ngắn hạn chiếm tỷ trọng lớn (1,080 tỷ VND trên tổng nợ 2,064 tỷ VND). Nợ ngắn hạn đã vượt quá tài sản ngắn hạn 101,790 triệu VND, cho thấy áp lực thanh khoản ngắn hạn. Nhiều khoản vay không có tài sản đảm bảo. Công ty phụ thuộc vào hạn mức tín dụng từ các tổ chức tín dụng để duy trì hoạt động.', 'Hàng tồn kho tăng mạnh từ 525 tỷ lên 723 tỷ VND, dự phòng giảm giá tăng từ 2 tỷ lên 55 tỷ VND, cho thấy rủi ro hàng hóa chậm luân chuyển hoặc giảm giá. Có khoản hàng hóa bất động sản (46 tỷ VND) bị phong tỏa do điều tra. Dự án xây dựng dở dang (Kho Khánh Hưng) đang tạm dừng chờ gia hạn.', 7, 'Tổng công ty đang trong tình trạng khó khăn tài chính với lỗ lũy kế lớn (2,651 tỷ VND), âm vốn chủ sở hữu nếu trừ đi vốn cổ phần. Hoạt động kinh doanh thua lỗ liên tiếp 2 năm (2020: -271 tỷ, 2021: -352 tỷ) do ảnh hưởng nặng nề của Covid-19 và thị trường gạo trầm lắng. Công ty có nhiều khoản đầu tư vào công ty con và liên kết đã dự phòng giảm giá toàn bộ, nhiều khoản phải thu khó đòi. Rủi ro quản trị ở mức cao do tồn tại nhiều giao dịch liên quan phức tạp, tài sản thiếu chờ xử lý lớn liên quan đến vụ án hình sự, và chưa quyết toán cổ phần hóa.'),
('VSF_2018_consolidated', 'VSF', 2018, 'consolidated', 'Tổng Công ty có mạng lưới công ty con, liên kết phức tạp với nhiều khoản đầu tư theo giá gốc do chưa có báo cáo tài chính hoặc đã ngưng hoạt động. Đáng chú ý: (1) Công ty CP Lương thực Hậu Giang (công ty con) tạm ngưng hoạt động, khoản đầu tư dự phòng tổn thất toàn bộ 28.771 tỷ đồng, và khoản phải thu 165.330 tỷ đồng cũng đã trích lập dự phòng 100% do liên quan đến nghĩa vụ bảo lãnh; (2) Công ty TNHH Lương thực V.A.P. đã dự phòng toàn bộ 43.875 tỷ đồng; (3) Nhiều khoản phải thu của khách hàng và trả trước cho người bán là bên liên quan có dự phòng lớn, cho thấy rủi ro thu hồi cao; (4) Các công ty liên kết như Vĩnh Long, Hoàn Mỹ, Cambodia-VN lỗ vượt vốn đầu tư. Mạng lưới giao dịch với các bên liên quan chồng chéo, đáng ngờ.', 'Áp lực nợ vay rất lớn với tổng nợ vay 3.329 tỷ VNĐ (ngắn hạn 3.297 tỷ + dài hạn 31,5 tỷ), chiếm khoảng 37% tổng tài sản. Nợ ngắn hạn tập trung tại nhiều ngân hàng lớn (HDBank, Vietcombank, Agribank, BIDV, BNP Paribas) với hạn mức tín dụng hàng nghìn tỷ đồng. Phần lớn nợ có hình thức bảo đảm bằng tài sản cố định (quyền sử dụng đất, nhà xưởng, kho lương thực, máy móc thiết bị) tại nhiều địa phương. Dòng tiền hoạt động kinh doanh kỳ này dương 730 tỷ đồng nhưng lỗ ròng 1.488 tỷ cho thấy áp lực trả nợ gốc và lãi vay rất lớn, đặc biệt lãi vay kỳ này là 35,7 tỷ đồng.', 'Tồn kho lớn 2.886 tỷ VNĐ (trừ dự phòng), trong đó hàng gửi đi bán chiếm 821 tỷ và nguyên liệu vật liệu 687 tỷ. Dự phòng giảm giá hàng tồn kho 66 tỷ đồng. Đáng lo ngại nhất là 662 tỷ đồng hàng tồn kho thiếu chờ xử lý tại Công ty Lương thực Trà Vinh đã trích lập dự phòng 100%, hiện cơ quan cảnh sát điều tra đang làm rõ. Nhiều dự án xây dựng cơ bản dở dang đã kéo dài nhiều năm (Kho chứa Ninh Quôi, KCN Tân Kim, Kho Khánh Hưng...) chưa hoàn thành, có nguy cơ ứ đọng vốn.', 8, 'Tổng Công ty Lương thực Miền Nam - CTCP đang trong tình trạng tài chính nghiêm trọng. Kỳ kế toán 09/10-31/12/2018 ghi nhận lỗ sau thuế 1.488 tỷ VNĐ, chủ yếu do trích lập dự phòng nợ phải thu khó đòi 640 tỷ, dự phòng đầu tư tài chính 108 tỷ, và chi phí quản lý doanh nghiệp tăng vọt lên 1.288 tỷ (bao gồm dự phòng). Lợi nhuận sau thuế chưa phân phối lũy kế âm 1.965 tỷ VNĐ, vượt quá 39% vốn chủ sở hữu. Kiểm toán viên đưa ra ý kiến ngoại trừ do: (i) bất động sản chuyển nhượng chưa ghi nhận doanh thu; (ii) khoản đầu tư vào công ty con tạm ngưng; (iii) đầu tư liên kết không có BCTC. Báo cáo kiểm toán cũng nêu nhiều vấn đề cần nhấn mạnh về cổ phần hóa, tài sản thiếu chờ xử lý, phương án sử dụng đất chưa thống nhất. Doanh nghiệp có hệ sinh thái con-liên kết phức tạp, nhiều khoản đầu tư và phải thu đã trích lập dự phòng toàn bộ. Triển vọng đầu tư rất rủi ro.'),
('VSF_2021_consolidated', 'VSF', 2021, 'consolidated', 'Rủi ro cao. Công ty có khoản phải thu 54,4 tỷ VND và trả trước 73,2 tỷ VND cho Công ty Lương thực Hậu Giang (công ty con ngừng hoạt động từ 2014, đang phá sản theo Quyết định Tuyên bố phá sản 01/2020/QĐ-PS). Toàn bộ đã dự phòng tổn thất. Ngoài ra có khoản trả trước cho người bán 9,5 tỷ VND từ cùng công ty con này. Phải trả dài hạn cho Công ty CP Đầu tư Địa ốc Bến Thành (bên liên quan) 5 tỷ VND tiền hợp tác kinh doanh. Khoản phải thu Chính phủ Cuba 587 tỷ VND có bản chất viện trợ, tương ứng phải trả Nhà nước cùng số tiền.', 'Rủi ro rất cao. Nợ vay ngắn hạn 1.885 tỷ VND, tăng mạnh so với 1.452 tỷ VND đầu năm. Nợ dài hạn 6,2 tỷ VND. Tổng nợ phải trả 4.030 tỷ VND chiếm 61,8% tổng tài sản 6.525 tỷ VND. Công ty có lỗ lũy kế -2.807 tỷ VND, vốn chủ sở hữu thực chất âm nếu loại trừ vốn cổ phần 5.000 tỷ. Lưu chuyển tiền thuần từ hoạt động kinh doanh âm -574,9 tỷ VND (năm trước dương +829 tỷ). Hàng tồn kho và quyền sử dụng đất được thế chấp cho nhiều khoản vay. Chi phí lãi vay 117,2 tỷ VND/năm.', 'Rủi ro rất cao. Tổng hàng tồn kho 1.308 tỷ VND (sau dự phòng). Dự phòng giảm giá tăng mạnh từ 50,8 tỷ lên 108,2 tỷ VND. Hàng hóa bất động sản 54,4 tỷ VND bị phong tỏa do điều tra. Hàng tồn kho thiếu chờ xử lý 668,5 tỷ VND đã dự phòng toàn bộ liên quan đến vụ tham ô tại Công ty Lương thực Trà Vinh, đang chờ phán quyết phúc thẩm. Dự án nhà máy chế biến nông sản và kho Khánh Hưng đều tạm ngưng nhiều năm chưa triển khai lại.', 8, 'Tổng Công ty Lương thực Miền Nam đang trong tình trạng tài chính nghiêm trọng: (1) Lỗ lũy kế -2.807 tỷ VND, vốn chủ sở hữu thực âm nếu trừ vốn cổ phần; (2) Doanh thu ổn định ~16.500 tỷ nhưng biên lợi nhuận gộp chỉ 5,7%, chi phí bán hàng và quản lý cao; (3) Nợ vay ngắn hạn tăng 434 tỷ trong năm lên 1.885 tỷ, dòng tiền hoạt động kinh doanh âm -575 tỷ; (4) Nhiều vấn đề lịch sử từ cổ phần hóa chưa được quyết toán, tài sản đất đai có tranh chấp với các cơ quan Nhà nước; (5) Đầu tư vào công ty con phá sản, hàng tồn kho thiếu lớn do tham ô với vụ án hình sự; (6) Kiểm toán viên đưa ra ý kiến ngoại trừ do không thể thu thập thông tin từ Công ty Lương thực Hậu Giang. Rủi ro đầu tư cực kỳ cao, triển vọng phụ thuộc vào quyết toán cổ phần hóa và khả năng tái cơ cấu nợ.'),
('VSF_2017_parent', 'VSF', 2017, 'parent', 'Tổng Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm bán hàng, cung cấp dịch vụ, chia cổ tức, lãi ứng vốn và phí bảo lãnh. Các khoản phải thu từ bên liên quan khá lớn (76.8 tỷ VND), đặc biệt khoản phải thu từ Công ty CP Tô Châu (28.4 tỷ VND) đã được trích lập dự phòng 100% do không có khả năng thu hồi. Các giao dịch này cho thấy sự phụ thuộc và liên kết chặt chẽ nhưng cũng tiềm ẩn rủi ro về công nợ khó đòi và thiếu minh bạch.', 'Tổng nợ vay chiếm tỷ trọng cao trong cơ cấu vốn, với tổng nợ vay ngắn hạn và dài hạn lên đến hơn 2,317 tỷ VND. Áp lực nợ vay là đáng kể, đặc biệt khi công ty đang trong quá trình cổ phần hóa và có lỗ lũy kế lớn (-918.8 tỷ VND). Nhiều khoản vay được đảm bảo bằng bảo lãnh của Tổng Công ty, tạo rủi ro tập trung. Khả năng thanh toán nợ phụ thuộc vào dòng tiền kinh doanh và thoái vốn đầu tư.', 'Tồn kho có giá trị lớn (hơn 1,326 tỷ VND) bao gồm nguyên liệu, thành phẩm và hàng hóa bất động sản. Rủi ro chính là khoản tài sản thiếu chờ xử lý tại Công ty Lương thực Trà Vinh trị giá 661.9 tỷ VND do mất mát hàng tồn kho. Việc không trích lập dự phòng giảm giá hàng tồn kho trong năm (do cổ phần hóa) cũng tiềm ẩn rủi ro nếu giá trị thuần có thể thực hiện thấp hơn giá gốc.', 7, 'Tổng Công ty Lương thực Miền Nam (Vinafood II) là doanh nghiệp nhà nước lớn trong ngành lương thực, nhưng đang đối mặt với nhiều thách thức tài chính. Kết quả kinh doanh năm 2017 lỗ ròng 120.3 tỷ VND, với lỗ lũy kế lên đến 918.8 tỷ VND. Cơ cấu tài chính có đòn bẩy nợ cao, áp lực nợ vay lớn. Công ty đang trong quá trình cổ phần hóa phức tạp, với nhiều vấn đề tồn đọng về tài sản thiếu, nợ khó đòi và giao dịch bên liên quan. Triển vọng đầu tư bị hạn chế bởi các rủi ro quản trị, tài chính và vận hành, nhưng vẫn có tiềm năng từ quy mô và mạng lưới kinh doanh rộng khắp nếu quá trình tái cơ cấu thành công.'),
('VSF_2018_parent', 'VSF', 2018, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con và công ty liên kết, với số dư phải thu và phải trả lớn. Một số khoản phải thu đã trích lập dự phòng 100% do không có khả năng thu hồi, cho thấy rủi ro tín dụng cao trong nội bộ tập đoàn.', 'Áp lực nợ vay ngắn hạn cao với tổng nợ ngắn hạn hơn 2.363 tỷ VND, trong khi tiền mặt chỉ 256 tỷ VND. Chi phí lãi vay lớn, và nhiều khoản vay không có tài sản thế chấp (tín chấp), tăng rủi ro thanh khoản.', 'Hàng tồn kho giá trị lớn (gần 1.946 tỷ VND) với dự phòng giảm giá. Có tài sản thiếu chờ xử lý (661 tỷ VND) đang được điều tra, có thể gây tổn thất bổ sung.', 7, 'Doanh nghiệp đang trong tình trạng tài chính khó khăn với lỗ nặng trong kỳ, nợ vay cao, và ý kiến kiểm toán ngoại trừ. Rủi ro quản trị và tài chính đáng kể, triển vọng đầu tư tiêu cực.'),
('VSE_2024_consolidated', 'VSE', 2024, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với bên liên quan, đặc biệt là Tổng Công ty Đầu tư phát triển đường cao tốc Việt Nam (cổ đông lớn). Doanh thu từ các bên liên quan chiếm tỷ trọng cao (khoảng 70%), có thể ảnh hưởng đến tính độc lập và giá cả giao dịch công bằng.', 'Công ty không có nợ dài hạn, nợ ngắn hạn chủ yếu là phải trả người bán và chi phí phải trả. Tỷ lệ nợ trên tài sản thấp, áp lực thanh toán không cao, tài sản lưu động đủ để trang trải nợ ngắn hạn.', 'Tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, bao gồm các dự án từ nhiều năm trước như hạng mục Cầu Giế - Ninh Bình từ năm 2013, có nguy cơ chậm trễ quyết toán và có thể cần trích lập dự phòng giảm giá.', 5, 'Công ty có tình hình tài chính tương đối ổn định với lợi nhuận sau thuế dương năm 2024, sau khi lỗ năm 2023. Tuy nhiên, cần quan tâm đến các khoản phải thu lớn từ bên liên quan và tiến độ quyết toán các dự án tồn kho dở dang. Triển vọng phụ thuộc vào việc giải quyết các khoản nợ khó đòi và hiệu quả hoạt động kinh doanh trong tương lai.'),
('VSE_2022_consolidated', 'VSE', 2022, 'consolidated', 'Doanh thu và các khoản phải thu của Công ty phụ thuộc lớn vào cổ đông Tổng Công ty Đầu tư phát triển đường cao tốc Việt Nam (VEC). Các khoản phải thu từ VEC lên tới gần 26.000 tỷ VND, bao gồm cả khoản chờ quyết toán nhiều năm, tiềm ẩn rủi ro về thanh khoản và khả năng thu hồi. Giao dịch mua hàng với Công ty CP Vận hành và Bảo trì cũng tăng mạnh.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả nhà cung cấp ngắn hạn (13.266 tỷ VND). Tuy nhiên, Công ty có khoản phải thu khó đòi lớn đã trích lập dự phòng 7.334 tỷ VND (tương đương 100% giá trị) theo quy định, cho thấy chất lượng tài sản tài chính kém. Tiền và tương đương tiền cuối kỳ tăng mạnh nhờ thu hồi đầu tư, nhưng dòng tiền hoạt động kinh doanh âm.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (19.632 tỷ VND), không có dự phòng giảm giá. Các dự án xây dựng dở dang này có thể gặp rủi ro chậm trễ, đội vốn hoặc không được thanh toán, đặc biệt là hạng mục Cầu Giẽ - Ninh Bình đã kéo dài từ năm 2013.', 7, 'Công ty có tình hình tài chính ổn định về cơ cấu vốn (không nợ vay) nhưng hoạt động kinh doanh suy giảm mạnh năm 2022 (lợi nhuận sau thuế giảm 43%). Dòng tiền hoạt động kinh doanh âm, phụ thuộc vào thu hồi đầu tư. Rủi ro lớn nhất là tập trung vào khách hàng lớn (cổ đông VEC) và các khoản phải thu khó đòi, tồn kho dở dang kéo dài. Ý kiến kiểm toán ngoại trừ do chưa trích lập đủ dự phòng phải thu khó đòi.'),
('VSE_2025_consolidated', 'VSE', 2025, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với cổ đông lớn là Tổng Công ty Đầu tư phát triển đường cao tốc Việt Nam (VEC) với tổng doanh thu khoảng 27,5 tỷ VND và số phải thu cuối kỳ hơn 26,9 tỷ VND. Công ty CP Vận hành và bảo trì đường cao tốc Việt Nam cũng là bên liên quan (cùng nhà đầu tư, Chủ tịch HĐQT chung) với doanh thu gần 8 tỷ VND và phải thu 4 tỷ VND. Mức độ phụ thuộc vào giao dịch với các bên liên quan là tương đối cao, chiếm khoảng 39% tổng doanh thu. Các khoản phải thu từ VEC tăng mạnh từ 27 tỷ lên 35 tỷ VND trong năm, đặt ra câu hỏi về khả năng thu hồi và tính độc lập của các giao dịch.', 'Công ty không có nợ vay dài hạn, nợ ngắn hạn chủ yếu là phải trả người bán và chi phí phải trả. Chi phí lãi vay rất thấp chỉ 1,58 triệu VND. Tuy nhiên, áp lực nợ đến từ các khoản phải thu lớn (tổng phải thu ngắn hạn gần 70 tỷ VND) và dự phòng phải thu khó đòi tăng từ 10,9 tỷ lên 12,5 tỷ VND. Nhiều khoản phải thu khó đòi quá hạn trên 3 năm với tổng giá trị 12,46 tỷ VND, cho thấy khả năng thu hồi kém.', 'Rủi ro tồn kho là ĐÁNG BÁO ĐỘNG. Khoản chi phí SXKD dở dang cho Dự án Cầu Giế - Ninh Bình trị giá 6,88 tỷ VND đã tồn đọng từ năm 2013 (hơn 12 năm) và kiểm toán viên KHÔNG ĐÁNH GIÁ ĐƯỢC giá trị thuần có thể thực hiện được. Đây là cơ sở cho ý kiến kiểm toán ngoại trừ. Ngoài ra, nhiều công trình đã hoàn thành từ 2022 nhưng chưa quyết toán với VEC, tổng giá trị SXKD dở dang lên tới gần 24 tỷ VND.', 6, 'Công ty có sức khỏe tài cơ bản tốt với lợi nhuận sau thuế tăng 59% (từ 1,75 tỷ lên 2,79 tỷ VND), không có nợ dài hạn, dòng tiền hoạt động kinh doanh dương 4 tỷ VND. Biên lợi nhuận gộp đạt 13%. Tuy nhiên, có 3 rủi ro chính: (1) Ý kiến kiểm toán ngoại trừ liên quan đến khoản SXKD dở dang 6,88 tỷ VND tồn đọng 12 năm; (2) Nhiều khoản phải thu khó đòi trên 3 năm với tổng dự phòng 12,5 tỷ VND; (3) Phụ thuộc lớn vào giao dịch với VEC và các công ty liên quan. Triển vọng phụ thuộc vào khả năng quyết toán và thu hồi các khoản phải thu từ VEC.'),
('VSE_2023_consolidated', 'VSE', 2023, 'consolidated', 'Doanh thu năm 2023 chủ yếu đến từ Tổng Công ty Đầu tư Phát triển đường cao tốc Việt Nam (khoảng 75%), tạo ra rủi ro tập trung khách hàng cao. Giao dịch mua hàng với Công ty CP Vận hành và Bảo trì đường cao tốc Việt Nam cũng đáng chú ý.', 'Công ty không có nợ vay dài hạn, chỉ có nợ ngắn hạn phải trả nhà cung cấp. Áp lực nợ thấp, khả năng thanh toán ổn định, không có tài sản thế chấp nổi bật.', 'Hàng tồn kho chủ yếu là chi phí sản xuất dở dang từ các dự án xây dựng, nhiều khoản tồn động từ năm 2013 (như hạng mục Cầu Giế - Ninh Bình) và chưa được quyết toán, có nguy cơ không thu hồi được giá trị. Dự phòng giảm giá hàng tồn kho được trích lập nhưng không đầy đủ.', 5, 'Công ty lỗ sau thuế năm 2023 (-2,570,159,341 VND), doanh thu giảm so với năm trước, chi phí quản lý tăng cao. Phụ thuộc lớn vào một bên liên quan cho doanh thu. Có nhiều khoản tồn kho dở dang lâu năm chưa xử lý, ảnh hưởng đến dòng tiền và lợi nhuận. Tình hình tài chính không tốt, triển vọng đầu tư thận trọng.'),
('VSE_2018_consolidated', 'VSE', 2018, 'consolidated', 'Doanh thu tập trung cao vào một bên liên quan là Tổng Công ty Đầu tư phát triển đường cao tốc Việt Nam (chiếm trên 50% doanh thu), tạo ra rủi ro phụ thuộc. Các giao dịch với bên liên quan là giao dịch thương mại thông thường, không có dấu hiệu bất thường về giá hay điều kiện.', 'Công ty không có vay nợ ngân hàng, chỉ có các khoản phải trả nhà cung cấp ngắn hạn. Áp lực nợ thấp, khả năng thanh toán tốt. Tuy nhiên, có khoản chi phí phải trả lớn liên quan đến dự án, cần theo dõi tiến độ thanh toán.', 'Tồn kho bao gồm vật liệu xây dựng và hàng hóa, giảm so với năm trước. Dự án xây dựng dở dang có một số khoản chi phí từ năm 2013 chưa được quyết toán, tiềm ẩn rủi ro chậm thu hồi vốn.', 6, 'Công ty hoạt động có lợi nhuận nhưng giảm so với năm trước. Sức khỏe tài cơ bản tốt với tỷ lệ nợ vay thấp, dòng tiền kinh doanh dương. Tuy nhiên, tồn tại rủi ro tập trung doanh thu vào một khách hàng lớn, một số khoản phải thu khó đòi và dự án dở dang kéo dài. Triển vọng phụ thuộc lớn vào quan hệ với Tổng Công ty VEC và tiến độ quyết toán các dự án.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSE_2021_consolidated', 'VSE', 2021, 'consolidated', 'Công ty có doanh thu lớn với bên liên quan là Tổng Công ty Đầu tư Phát triển đường cao tốc Việt Nam (chiếm hơn 90% tổng doanh thu), tạo ra sự phụ thuộc đáng kể và rủi ro về tính độc lập trong kinh doanh.', 'Công ty không có khoản vay nợ đáng kể, chi phí lãi vay thấp (50.5 triệu VNĐ), áp lực trả nợ thấp và tài sản thế chấp không được đề cập.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang cho các dự án xây dựng, có nguy cơ chậm tiến độ hoặc giảm giá trị nếu dự án không hoàn thành đúng kế hoạch.', 5, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận sau thuế 3.16 tỷ VNĐ, nhưng phụ thuộc lớn vào một bên liên quan. Cơ cấu tài sản lành mạnh, không có nợ vay, nhưng cần giám sát các dự án dở dang và giao dịch với bên liên quan để đánh giá rủi ro dài hạn.'),
('VSC_2025_consolidated', 'VSC', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là dịch vụ cung cấp và mua dịch vụ, giá cả dựa trên điều kiện thị trường, không có dấu hiệu bất thường. Rủi ro thấp.', 'Nợ vay tăng mạnh để đầu tư dự án, chi phí lãi vay tăng 57%. Công ty có tài sản thế chấp, nhưng áp lực nợ vay đáng kể. Rủi ro trung bình.', 'Hàng tồn kho có giá trị thấp và không có dự phòng, cho thấy quản lý tồn kho hiệu quả. Rủi ro thấp.', 3, 'Công ty đạt lợi nhuận tăng trưởng tốt nhờ doanh thu và lợi nhuận từ công ty liên kết. Tuy nhiên, nợ vay tăng cao để tài trợ đầu tư, cần theo dõi khả năng thanh toán. Triển vọng đầu tư trung bình, phụ thuộc vào hiệu quả các dự án mới.'),
('VSC_2025_parent', 'VSC', 2025, 'parent', 'Công ty có giao dịch lớn với các bên liên quan (công ty con), bao gồm bán hàng, cung cấp dịch vụ, cho vay không lãi suất và không thời hạn (khoản phải trả ngắn hạn khác 158.7 tỷ VND), góp vốn vào công ty con. Các giao dịch này tuy là nội bộ tập đoàn nhưng cần giám sát để tránh xung đột lợi ích và đảm bảo tính công bằng.', 'Tổng nợ vay và nợ thuê tài chính ngắn hạn là 1,909 tỷ VND và dài hạn là 2,990 tỷ VND. Công ty vay lớn để đầu tư vào công ty con và dự án. Tài sản thế chấp bao gồm cổ phiếu, vốn góp và bất động sản. Áp lực trả nợ lãi và gốc là đáng kể, đặc biệt với các khoản vay lãi suất thả nổi.', 'Hàng tồn kho rất nhỏ (chỉ 469 triệu VND), không có rủi ro tồn kho dở dang hay dự án xây dựng dở dang.', 6, 'Công ty đạt lợi nhuận sau thuế tăng 175,95% nhờ thoái vốn đầu tư. Tuy nhiên, nợ vay tăng mạnh để tài trợ cho hoạt động đầu tư mở rộng. Công ty phụ thuộc lớn vào lợi nhuận từ hoạt động tài chính (cổ tức, lãi từ thoái vốn). Cần theo dõi khả năng thanh toán nợ và hiệu quả của các khoản đầu tư mới.'),
('VSE_2019_consolidated', 'VSE', 2019, 'consolidated', 'Doanh thu với các bên liên quan chiếm tỷ trọng cao (73.6% tổng doanh thu), trong đó chủ yếu là từ Tổng Công ty Đầu tư phát triển đường cao tốc Việt Nam (cổ đông sáng lập). Điều này tạo ra rủi ro tập trung khách hàng và phụ thuộc lớn vào bên liên quan.', 'Công ty gần như không có nợ vay tài chính (chỉ 99,000 VND), áp lực nợ vay thấp. Tuy nhiên, công ty có các khoản phải trả nhà thầu, chi phí phải trả lớn, thanh khoản dựa chủ yếu vào tiền gửi và đầu tư tài chính ngắn hạn.', 'Hàng tồn kho bao gồm chi phí xây dựng dở dang cho các dự án cụ thể (như tuyến Nội Bài - Lào Cai, Đà Nẵng - Quảng Ngãi). Giá trị tăng từ 12.5 tỷ lên 16.4 tỷ VND, có nguy cơ chậm tiến độ và thanh khoản thấp.', 5, 'Công ty hoạt động trong lĩnh vực xây dựng và dịch vụ đường cao tốc, có tỷ suất lợi nhuận gộp ~14.5%. Tuy nhiên, doanh thu giảm mạnh so với năm 2018 (-28%), phụ thuộc lớn vào một số bên liên quan lớn. Công ty có nền tảng tài sản vững (vốn chủ sở hữu 95 tỷ VND, không nợ vay) nhưng tồn tại rủi ro về thu hồi công nợ (dự phòng 5.8 tỷ VND) và tính thanh khoản của hàng tồn kho xây dựng dở dang.'),
('VSC_2024_consolidated', 'VSC', 2024, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan bao gồm công ty liên kết và công ty con, với tổng doanh thu bán hàng cho bên liên quan đạt hơn 421 tỷ đồng (chiếm khoảng 15% doanh thu thuần). Giao dịch mua dịch vụ từ bên liên quan đạt hơn 111 tỷ đồng. Các giao dịch này chủ yếu liên quan đến dịch vụ cảng biển, vận chuyển và hoa hồng đại lý. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn đáng kể với bên liên quan. Công ty có khoản đặt cọc lớn cho việc mua phần vốn góp Cảng Nam Hải Đình Vũ từ Công ty TNHH Đoàn Huy và Công ty TNHH Huy Hoàng trong năm 2023 đã được hoàn tất vào năm 2024.', 'Tổng nợ vay của Tập đoàn đạt khoảng 1.950 tỷ đồng, trong đó nợ ngắn hạn khoảng 300 tỷ đồng và nợ dài hạn khoảng 1.650 tỷ đồng. Áp lực nợ vay tăng đáng kể do Công ty vay lớn từ Eximbank Chi nhánh Hải Phòng (hơn 1.647 tỷ đồng)主要用于 tái cấu trúc khoản vay và thanh toán tiền mua phần vốn góp Cảng Nam Hải Đình Vũ. Lãi suất vay dài hạn là 7%/năm cho giai đoạn đầu, sau đó thả nổi theo lãi suất cơ sở. Tài sản thế chấp bao gồm toàn bộ quyền sử dụng đất và tài sản trên đất, máy móc, thiết bị tại Cảng Nam Hải Đình Vũ. Chi phí lãi vay năm 2024 là 167 tỷ đồng, giảm nhẹ so với năm 2023 (170 tỷ đồng) mặc dù nợ tăng do Công ty đã tất toán sớm các khoản vay cũ.', 'Hàng tồn kho của Tập đoàn có giá trị tương đối nhỏ (khoảng 47,5 tỷ đồng, chiếm chưa đến 1% tổng tài sản), bao gồm nguyên vật liệu, công cụ dụng cụ và hàng hóa. Không có dự phòng giảm giá hàng tồn kho. Chi phí xây dựng cơ bản dở dang chỉ có 396 triệu đồng, mức rất thấp. Rủi ro tồn kho thấp do đặc thù ngành dịch vụ cảng biển không cần dự trữ hàng hóa lớn.', 4, 'Công ty CP Container Việt Nam có sức khỏe tài chính tốt với lợi nhuận sau thuế tăng 118,3% so với cùng kỳ, đạt 434,5 tỷ đồng. Doanh thu cung cấp dịch vụ tăng 27,8%, lợi nhuận gộp tăng 29%. Doanh thu tài chính tăng mạnh 748% nhờ ghi nhận giá trị hợp lý khoản đầu tư vào Công ty liên kết (Cảng Nam Hải Đình Vũ) và lãi từ kinh doanh chứng khoán. Biên lợi nhuận gộp đạt 30,25%, cho thấy hiệu quả hoạt động tốt. Công ty đã thực hiện thành công thương vụ M&A Cảng Nam Hải Đình Vũ, mở rộng đáng kể quy mô hoạt động. Lợi thế thương mại đạt 450 tỷ đồng. Tuy nhiên, nợ vay tăng mạnh để tài trợ M&A, tạo áp lực trả nợ trong trung hạn. Tổng tài sản đạt 7.795 tỷ đồng, tăng 50% so với đầu năm chủ yếu do hợp nhất. Công ty có dòng tiền hoạt động kinh doanh dương (13,8 tỷ đồng) nhưng thấp hơn nhiều so với lợi nhuận kế toán, do vốn lưu động tăng.'),
('VSC_2023_consolidated', 'VSC', 2023, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cung cấp và mua dịch vụ với các công ty liên kết và công ty liên quan khác. Giá trị giao dịch lớn, đặc biệt với Công ty TNHH Đại lý Vận tải Evergreen (Việt Nam), nhưng không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, khoản lỗ trong công ty liên kết đáng lưu ý.', 'Nợ vay tăng mạnh trong năm 2023, đặc biệt nợ dài hạn, dẫn đến chi phí lãi vay tăng vọt. Công ty đã sử dụng nhiều tài sản thế chấp cho các khoản vay ngân hàng, tạo áp lực thanh toán và rủi ro tài chính nếu dòng tiền không đảm bảo.', 'Hàng tồn kho có giá trị tương đối nhỏ và không có dự phòng, cho thấy rủi ro tồn kho thấp. Tuy nhiên, cần theo dõi khả năng lưu chuyển của hàng hóa.', 5, 'Công ty tăng trưởng doanh thu 8,6% nhưng lợi nhuận giảm 49,3% do chi phí lãi vay tăng cao từ hoạt động đầu tư. Nợ vay gia tăng làm tăng rủi ro tài chính, nhưng các giao dịch với bên liên quan không có biểu hiện bất thường lớn. Công ty đang trong giai đoạn đầu tư mạnh vào hạ tầng logistics và khách sạn, triển vọng dài hạn phụ thuộc vào hiệu quả của các dự án này.'),
('VSC_2024_parent', 'VSC', 2024, 'parent', 'Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm cho vay, mua bán dịch vụ và chia cổ tức. Các giao dịch này được thực hiện theo giá thị trường và có mục đích hỗ trợ hoạt động kinh doanh, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay tăng mạnh, chủ yếu là nợ dài hạn để tài trợ cho việc mua lại Cảng Nam Hải Đình Vũ. Lãi suất vay cao (7%/năm) tạo áp lực chi phí tài chính. Tuy nhiên, công ty có tài sản thế chấp lớn và dòng tiền từ hoạt động đầu tư có thể hỗ trợ thanh toán.', 'Giá trị hàng tồn kho rất nhỏ, không có dự phòng giảm giá, cho thấy rủi ro tồn kho thấp. Công ty không có dự án xây dựng dở dang hay bất động sản tồn đọng.', 3, 'Công ty có kết quả kinh doanh tăng trưởng mạnh nhờ doanh thu tài chính từ cổ tức và lãi đầu tư. Nợ vay tăng cao để phục vụ mở rộng, nhưng khả năng sinh lời từ các khoản đầu tư có thể bù đắp. Tình hình tài chính ổn định, không có rủi ro lớn về quản trị hay hoạt động.'),
('VSC_2022_consolidated', 'VSC', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cung cấp và mua dịch vụ, chi phí hoa hồng và khoản phải thu/phải trả phát sinh từ hoạt động kinh doanh thông thường. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Công ty có tổng nợ vay ngắn hạn 208.4 tỷ và dài hạn 700 tỷ VND. Các khoản vay đều có tài sản đảm bảo là quyền tài sản và cổ phiếu. Áp lực nợ vay vừa phải do dòng tiền kinh doanh mạnh, nhưng cần theo dõi khả năng thanh toán khi đến hạn.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ và nguyên vật liệu, không có hàng tồn kho dở dang lớn. Dự phòng tồn kho là 0, cho thấy rủi ro tồn kho thấp.', 4, 'Công ty Container Việt Nam (VSC) có sức khỏe tài chính tốt với doanh thu và lợi nhuận tăng trưởng, tỷ suất lợi nhuận gộp cao (32.8%). Cơ cấu tài sản dài hạn tăng mạnh do đầu tư và hợp nhất kinh doanh. Dòng tiền kinh doanh dương mạnh, nhưng dòng tiền đầu tư âm lớn do các khoản đầu tư vào công ty con và tài sản. Công ty có hệ thống quản trị minh bạch với các giao dịch bên liên quan được công bố rõ ràng. Điểm rủi ro quản trị ở mức trung bình (4/10) do có một số giao dịch lớn với bên liên quan và nợ vay có tài sản đảm bảo.'),
('VSC_2023_parent', 'VSC', 2023, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con và liên kết, bao gồm cho vay không lãi suất và không thời hạn thu hồi (ví dụ: khoản tạm ứng cho công ty con), điều này tiềm ẩn rủi ro về quản trị và thanh khoản. Tuy nhiên, giao dịch chủ yếu là thương mại và đầu tư, không thấy bất thường nghiêm trọng.', 'Áp lực nợ vay cao với tổng nợ vay trên 862 tỷ VNĐ, trong đó nợ dài hạn lãi suất 14%/năm được dùng để đầu tư vào Cảng Nam Hải Đình Vũ. Công ty phải trả nợ gốc định kỳ và lãi vay, có tài sản thế chấp nhưng dòng tiền hoạt động kinh doanh âm, tạo rủi ro thanh toán.', 'Hàng tồn kho rất thấp chỉ 24 triệu VNĐ, giảm mạnh so với năm trước, cho thấy không có rủi ro tồn kho dở dang hay ứ đọng.', 6, 'Công ty Container Việt Nam (VSC) có doanh thu giảm mạnh 63% do ngừng mảng đại lý tàu biển, nhưng lợi nhuận gộp tăng nhờ quản lý giá vốn. Tuy nhiên, lợi nhuận sau thuế giảm 37% do chi phí tài chính tăng cao từ đầu tư và dự phòng. Công ty đang mở rộng đầu tư vào cảng biển qua các khoản vay dài hạn, dẫn đến đòn bẩy tài chính tăng và dòng tiền hoạt động kinh doanh âm. Triển vọng phụ thuộc vào hiệu quả các dự án đầu tư và khả năng kiểm soát chi phí.'),
('VSC_2022_parent', 'VSC', 2022, 'parent', 'Giao dịch với bên liên quan (công ty con, liên kết) diễn ra thường xuyên và có giá trị lớn, đặc biệt là doanh thu bán hàng, dịch vụ, cho vay và chia lợi nhuận. Các khoản cho vay có lãi suất thỏa thuận (5.1%-5.7%/năm) và mục đích hỗ trợ hoạt động sản xuất kinh doanh. Mối quan hệ phức tạp với nhiều công ty con đòi hỏi sự giám sát chặt chẽ để tránh xung đột lợi ích, nhưng các giao dịch này có vẻ được thực hiện theo giá thị trường hoặc thỏa thuận thương mại thông thường.', 'Áp lực nợ vay ngắn hạn thấp, chỉ có một khoản vay lớn 171.8 tỷ VNĐ từ Công ty TNHH Thương mại và Đầu tư Đoàn Huy được miễn lãi đến tháng 3/2023. Công ty có lượng tiền và đầu tư ngắn hạn lớn (gần 26 tỷ VNĐ tiền gửi có kỳ hạn và 26 tỷ VNĐ đầu tư đáo hạn), cùng với dòng tiền thuần từ hoạt động kinh doanh năm trước dương, cho thấy khả năng thanh toán nợ tốt. Không có tài sản thế chấp lớn nào được nêu cho khoản vay này.', 'Rủi ro tồn kho thấp. Giá trị hàng tồn kho chỉ hơn 1.18 tỷ VNĐ, chiếm tỷ trọng rất nhỏ trong tổng tài sản, chủ yếu là vật tư, nhiên liệu phục vụ kinh doanh. Không có dự phòng giảm giá tồn kho.', 6, 'Công ty Container Việt Nam (VSC) có nền tảng tài chính vững mạnh với tỷ suất lợi nhuận gộp tốt (khoảng 6.8%), hoạt động đầu tư tài chính (vào các công ty con, liên kết) mang lại nguồn thu nhập tài chính khổng lồ (283 tỷ VNĐ). Công ty đang trong giai đoạn mở rộng mạnh mẽ thông qua tăng vốn và đầu tư vào logistics, cảng biển. Tuy nhiên, rủi ro quản trị ở mức trung bình cao do sự phức tạp trong mạng lưới công ty con/liên kết và tần suất thay đổi nhân sự cấp cao (Hội đồng Quản trị, Ban Giám đốc). Sức khỏe tài chính tổng thể tốt, thanh khoản đảm bảo, nhưng tăng trưởng và lợi nhuận tương lai phụ thuộc lớn vào hiệu quả hoạt động của các khoản đầu tư chiến lược.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSC_2021_consolidated', 'VSC', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cung cấp và mua dịch vụ, tỷ trọng không quá lớn so với tổng tài sản và doanh thu, không có dấu hiệu bất thường.', 'Nợ phải trả chủ yếu là ngắn hạn và giảm so với năm trước, công ty có lượng tiền mặt dồi dào nên áp lực trả nợ thấp.', 'Hàng tồn kho giảm và không có dự phòng, chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có dự án xây dựng dở dang.', 2, 'Tình hình tài chính hợp nhất của Tập đoàn phản ánh trung thực và hợp lý, lợi nhuận sau thuế tăng 39.61% so với năm trước, doanh thu tăng trưởng, chi phí được kiểm soát tốt. Công ty có tiềm lực tài chính mạnh với tiền mặt lớn, đầu tư vào công ty liên kết và phát hành cổ phiếu tăng vốn. Triển vọng đầu tư tích cực.'),
('VSC_2021_parent', 'VSC', 2021, 'parent', 'Công ty có nhiều giao dịch với công ty con và công ty liên kết, chủ yếu là bán hàng hóa, cung cấp dịch vụ, cho vay và thu hộ/trả hộ. Các giao dịch này chiếm tỷ trọng lớn trong doanh thu và lợi nhuận. Tuy nhiên, chưa thấy có giao dịch bất thường rõ ràng về giá hay điều kiện.', 'Công ty gần như không có nợ vay tài chính (ngắn hạn và dài hạn) từ các tổ chức tín dụng. Các khoản nợ phải trả chủ yếu là phải trả người bán và các khoản phải trả khác. Áp lực nợ vay thấp.', 'Hàng tồn kho có giá trị không lớn và tăng so với năm trước. Rủi ro tồn kho thấp do đây là hoạt động thương mại.', 2, 'Công ty hoạt động kinh doanh chính là cung cấp dịch vụ logistics, vận tải, kho bãi. Kết quả kinh doanh năm 2021 tăng mạnh chủ yếu nhờ doanh thu từ hoạt động tài chính (cổ tức, lãi cho vay từ các công ty con/liên kết) và doanh thu dịch vụ tăng. Công ty có cơ cấu tài chính lành mạnh, không có nợ vay, dòng tiền kinh doanh dương. Tuy nhiên, sự phụ thuộc lớn vào lợi nhuận từ đầu tư tài chính (cổ tức từ công ty con/liên kết) có thể là rủi ro nếu hoạt động của các công ty này suy giảm. Công ty đã tăng vốn thành công năm 2021 để mở rộng hoạt động.'),
('VSC_2020_consolidated', 'VSC', 2020, 'consolidated', 'Tập đoàn có giao dịch lớn với các công ty liên kết (tổng giá trị giao dịch mua/bán dịch vụ hơn 200 tỷ VNĐ). Các khoản phải thu và phải trả với các bên liên quan không tính lãi và không có tài sản đảm bảo. Mặc dù chưa phát hiện bất thường rõ ràng về giá chuyển giao, nhưng quy mô giao dịch lớn và tập trung vào một số ít đối tượng liên kết cần được giám sát chặt chẽ.', 'Áp lực nợ vay thấp do Công ty đã trả toàn bộ nợ vay ngắn hạn và dài hạn trong năm 2020. Các khoản nợ phải trả chủ yếu là nợ thương mại phải trả người bán ngắn hạn và các khoản phải trả khác. Tài sản thế chấp không được đề cập chi tiết trong thuyết minh.', 'Hàng tồn kho giảm nhẹ từ 26.4 tỷ xuống 24.5 tỷ VNĐ, chủ yếu là nguyên vật liệu và hàng hóa. Không có hàng tồn kho dở dang hay dự án xây dựng lớn tồn đọng. Rủi ro tồn kho ở mức thấp.', 4, 'Công ty Cổ phần Container Việt Nam có sức khỏe tài chính tốt trong năm 2020 với lợi nhuận sau thuế tăng nhẹ (296.4 tỷ VNĐ so với 285.8 tỷ năm 2019). Công ty không có nợ vay, sở hữu lượng tiền mặt lớn (hơn 493 tỷ VNĐ) và dòng tiền hoạt động kinh doanh mạnh (hơn 529 tỷ). Tuy nhiên, doanh thu giảm nhẹ do ảnh hưởng của dịch bệnh. Triển vọng đầu tư tích cực nhờ vị thế tài chính vững mạnh và ngành kinh doanh logistics thiết yếu.'),
('VSC_2019_consolidated', 'VSC', 2019, 'consolidated', 'Công ty có phát sinh giao dịch mua bán dịch vụ với các công ty liên kết, chủ yếu là Công ty Cổ phần Cảng dịch vụ Dầu khí Đình Vũ và Công ty TNHH Tuyến Container T.S Hà Nội. Giá trị giao dịch lớn nhưng được thuyết minh là giao dịch thương mại bình thường (cung cấp và sử dụng dịch vụ) và không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Nợ vay giảm mạnh từ 273 tỷ (ngắn và dài hạn) xuống còn 76 tỷ, cho thấy áp lực trả nợ giảm đáng kể. Các khoản vay dài hạn đều có tài sản đảm bảo là tài sản cố định của các công ty con, tỷ lệ an toàn cao. Tuy nhiên, vẫn cần theo dõi tiến độ trả nợ của khoản vay đáo hạn vào năm 2025.', 'Tồn kho chủ yếu là nguyên vật liệu (24 tỷ) và hàng hóa (2.3 tỷ), mức tồn kho tăng so với đầu năm nhưng không có dấu hiệu ứ đọng lớn. Dự án xây dựng cơ bản dở dang chỉ còn 80 triệu, không đáng kể.', 4, 'Công ty ghi nhận sự sụt giảm lợi nhuận sau thuế 22% so với năm trước do doanh thu container lạnh giảm và chi phí khai thác tăng. Tuy nhiên, điểm sáng là công ty đã giảm mạnh nợ vay, cải thiện đáng kể cơ cấu vốn và giảm rủi ro tài chính. Dòng tiền từ hoạt động kinh doanh vẫn dương mạnh. Công ty duy trì quan hệ kinh doanh chính với các công ty liên kết và các hãng tàu lớn. Rủi ro quản trị ở mức trung bình thấp, không phát hiện giao dịch bất thường lớn với bên liên quan. Triển vọng trung hạn phụ thuộc vào sự phục hồi của thị trường logistics và container.'),
('VSC_2020_parent', 'VSC', 2020, 'parent', 'Công ty có giao dịch lớn với các công ty con, bao gồm cho vay không lãi suất, mua bán hàng hóa/dịch vụ và nhận cổ tức. Các khoản phải thu từ bên liên quan chiếm tỷ trọng lớn, có thể tiềm ẩn rủi ro tập trung và lợi ích nhóm.', 'Công ty gần như không có nợ vay ngân hàng, nợ dài hạn chỉ 30 triệu VND. Nợ ngắn hạn chủ yếu là phải trả người bán và thuế, không gây áp lực tài chính lớn.', 'Hàng tồn kho giảm mạnh (từ 7.7 tỷ xuống 0.47 tỷ VND) do chuyển giao hoạt động kinh doanh cảng sang công ty con, rủi ro tồn kho thấp.', 6, 'Doanh thu và lợi nhuận giảm mạnh do không còn hợp nhất hoạt động của Xí nghiệp Cảng Viconship. Công ty có giao dịch lớn với các công ty con, cần đánh giá tính minh bạch. Tình hình tài khỏe mạnh với lượng tiền mặt dồi dào, không có nợ vay áp lực. Tuy nhiên, sự phụ thuộc vào cổ tức từ công ty con là nguồn thu nhập chính.'),
('VSC_2018_parent', 'VSC', 2018, 'parent', 'Doanh nghiệp có quan hệ giao dịch phức tạp và thường xuyên với các công ty con và công ty liên kết, bao gồm cho vay không có tài sản đảm bảo, mua bán dịch vụ nội bộ với giá trị lớn. Các khoản phải thu ngắn hạn và dài hạn từ các bên liên quan là đáng kể (hơn 155 tỷ VNĐ), tạo ra rủi ro về thanh khoản và tập trung tín dụng. Tuy nhiên, các khoản vay đều có thỏa thuận về lãi suất (theo lãi suất tiết kiệm VND kỳ hạn 12 tháng cộng thêm một biên độ) và thời hạn trả nợ rõ ràng, giảm bớt phần nào rủi ro.', 'Áp lực nợ vay thấp. Công ty không ghi nhận nợ vay tài chính dài hạn hay ngắn hạn từ bên thứ ba trên bảng cân đối kế toán riêng. Các khoản nợ phải trả chủ yếu là nợ thương mại với nhà cung cấp, thuế và các khoản phải nộp cho Nhà nước. Công ty có vị thế tiền mặt mạnh (hơn 184 tỷ VNĐ tiền và tương đương tiền) và tỷ lệ nợ trên vốn chủ sở hữu cực kỳ thấp, cho thấy khả năng thanh toán và an toàn tài chính cao.', 'Tồn kho chủ yếu là nguyên vật liệu và hàng hóa, với giá trị tương đối nhỏ (khoảng 5,6 tỷ VNĐ) so với tổng tài sản. Rủi ro tồn kho thấp, không có dấu hiệu của hàng tồn kho dở dang hay dự án xây dựng dở dang bị ứ đọng trong báo cáo riêng này.', 6, 'Công ty Cổ phần Container Việt Nam có sức khỏe tài chính vững mạnh với vị thế tiền mặt dồi dào, gần như không có nợ vay tài chính bên ngoài, và biên lợi nhuận gộp ổn định (~23%). Tuy nhiên, một phần đáng kể hoạt động kinh doanh và tài sản tồn tại dưới dạng giao dịch nội bộ và đầu tư vào hệ sinh thái công ty con/liên kết, tạo ra rủi ro tập trung và liên kết. Ban lãnh đạo có mối quan hệ kinh doanh sâu rộng với các bên liên quan, cần được giám sát. Triển vọng kinh doanh tích cực dựa trên tăng trưởng doanh thu và lợi nhuận, nhưng cần chú trọng quản trị rủi ro hệ thống nội bộ.'),
('VSC_2019_parent', 'VSC', 2019, 'parent', 'Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm cho vay không lãi suất, mua bán dịch vụ và chia cổ tức lớn. Điều này có thể tạo ra rủi ro về xung đột lợi ích và giao dịch không công bằng.', 'Nợ chủ yếu là phải trả người bán ngắn hạn, không có nợ vay ngân hàng. Áp lực nợ thấp và tài sản thế chấp không được đề cập, cho thấy rủi ro nợ thấp.', 'Hàng tồn kho bao gồm nguyên vật liệu và hàng hóa với giá trị tương đối nhỏ, không có dự án xây dựng dở dang. Rủi ro tồn kho thấp.', 6, 'Công ty có tình hình tài chính ổn định, lợi nhuận tăng trưởng 22% năm 2019 chủ yếu từ cổ tức công ty con. Tuy nhiên, sự phụ thuộc vào giao dịch liên quan và cơ cấu cổ đông phức tạp có thể ảnh hưởng đến triển vọng dài hạn.'),
('VSC_2018_consolidated', 'VSC', 2018, 'consolidated', 'Công ty có các giao dịch lớn với các công ty liên kết, bao gồm cung cấp và sử dụng dịch vụ, và nhận cổ tức. Các khoản phải thu và phải trả với bên liên quan không có đảm bảo và không tính lãi, cho thấy có thể có rủi ro liên quan đến điều kiện giao dịch không rõ ràng.', 'Tổng nợ phải trả là 544.5 tỷ VNĐ, với các khoản vay dài hạn được đảm bảo bằng tài sản cố định của các công ty con. Lãi suất khoảng 6.8-7%/năm, áp lực nợ vay có thể quản lý được nhưng cần theo dõi.', 'Hàng tồn kho ở mức 20.5 tỷ VNĐ, chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng giảm giá. Xây dựng cơ bản dở dang giảm đáng kể so với đầu năm, cho thấy tiến độ triển khai dự án.', 4, 'Công ty có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng trưởng, tỷ suất lợi nhuận gộp khoảng 29%. Nợ vay được đảm bảo và quản lý tốt, tuy nhiên cần chú ý đến giao dịch với bên liên quan và rủi ro liên quan đến chuỗi cung ứng.'),
('VSC_2017_consolidated', 'VSC', 2017, 'consolidated', 'Các giao dịch với các bên liên quan chủ yếu là dịch vụ và đầu tư, không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Nợ vay được đảm bảo bằng tài sản cố định của các công ty con, nhưng tổng nợ vay (gần 1.000 tỷ VNĐ) so với vốn chủ sở hữu (hơn 1.700 tỷ VNĐ) cho thấy áp lực trả nợ trung bình.', 'Hàng tồn kho tăng so với đầu năm, xây dựng cơ bản dở dang lớn (hơn 74 tỷ VNĐ) có thể ảnh hưởng đến dòng tiền nếu dự án chậm tiến độ.', 3, 'Công ty có doanh thu tăng trưởng 20%, lợi nhuận ổn định, tài sản cố định lớn. Tuy nhiên, nợ vay dài hạn cao và xây dựng dở dang tiềm ẩn rủi ro. Quản trị công ty tương đối minh bạch với giao dịch bên liên quan rõ ràng.'),
('VSC_2016_parent', 'VSC', 2016, 'parent', 'Công ty có hệ sinh thái giao dịch bên liên quan phức tạp với 6 công ty con và 2 công ty liên kết. Các khoản phải thu từ công ty con (Phải thu ngắn hạn khác) lên tới 171.6 tỷ VND, không tính lãi và không có đảm bảo. Công ty cho vay lớn cho Cảng Xanh VIP (tổng gốc cho vay ~86 tỷ VND) và Container Miền Trung (4.7 tỷ VND). Giao dịch mua bán dịch vụ qua lại lớn với Trung tâm Logistic Xanh (sử dụng dịch vụ 33.6 tỷ VND). Tuy nhiên, các giao dịch này có vẻ là giao dịch thương mại bình thường trong chuỗi logistics cảng biển.', 'Áp lực nợ vay rất thấp. Tổng vay ngân hàng chỉ 4.83 tỷ VND vay ngắn hạn từ Vietcombank, lãi suất 4%/năm (vay USD), đáo hạn 2017. Tỷ lệ nợ/vốn chủ sở hữu chỉ ~12.8% (166.7 tỷ / 1,303 tỷ). Có tài sản cố định thế chấp đảm bảo. Công ty có lượng tiền và tương đương tiền lớn (243.5 tỷ VND) và đầu tư nắm giữ đến đáo hạn (25 tỷ VND) đủ khả năng thanh toán nợ.', 'Hàng tồn kho giảm từ 8.4 tỷ xuống 6.8 tỷ VND, mức thấp và không có dự phòng giảm giá. Dự án xây dựng nhà kho số 3 tại Cảng Viconship trị giá 5.5 tỷ VND là dự án mới bắt đầu trong năm 2016, quy mô nhỏ so với tổng tài sản. Rủi ro tồn kho thấp.', 5, 'Công ty Cổ phần Container Việt Nam có nền tảng tài chính vững mạnh với vốn chủ sở hữu 1,303 tỷ VND, nợ vay rất thấp. Lợi nhuận sau thuế 213.7 tỷ VND, biên lợi nhuận gộp 40.9%. Tuy nhiên doanh thu giảm mạnh 27.3% (từ 665 tỷ xuống 483 tỷ VND) do suy giảm hoạt động vận tải biển và cảng. Công ty hưởng lợi lớn từ cổ tức và lãi cho vay từ các công ty con/liên kết (doanh thu tài chính 74.3 tỷ VND). Điểm rủi ro: phụ thuộc nhiều vào hệ sinh thái công ty con/liên kết, doanh thu sụt giảm, và tỷ lệ chi trả cổ tức cao (86.9 tỷ VND năm 2016). Triển vọng trung hạn phụ thuộc vào sự phục hồi của ngành vận tải biển và logistics cảng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSC_2016_consolidated', 'VSC', 2016, 'consolidated', 'Giao dịch với các bên liên quan bao gồm cung cấp và sử dụng dịch vụ, cổ tức, lương thưởng cho ban lãnh đạo, không có dấu hiệu bất thường nhưng giá trị giao dịch lớn cần giám sát.', 'Nợ vay tăng đáng kể, đặc biệt nợ dài hạn với lãi suất cố định, có tài sản cố định thế chấp đảm bảo, áp lực trả nợ trong ngắn hạn do khoản đến hạn lớn.', 'Hàng tồn kho giảm nhẹ, xây dựng cơ bản dở dang giảm mạnh cho thấy tiến độ hoàn thành các dự án, không có dấu hiệu ứ đọng lớn.', 3, 'Doanh nghiệp có lợi nhuận tốt, tăng trưởng doanh thu, tỷ lệ lợi nhuận gộp cao, nợ vay có tài sản bảo đảm, quản trị minh bạch, triển vọng kinh doanh ổn định trong ngành logistics và cảng biển.'),
('VSC_2017_parent', 'VSC', 2017, 'parent', 'Công ty có nhiều giao dịch lớn với các công ty con và liên kết, bao gồm cho vay không có tài sản đảm bảo, không tính lãi. Các khoản phải thu ngắn hạn khác từ công ty con lên đến hơn 119 tỷ VNĐ, không đảm bảo và không lãi suất. Điều này tiềm ẩn rủi ro về khả năng thu hồi nếu công ty con gặp khó khăn tài chính.', 'Tổng nợ phải trả giảm mạnh từ 166.66 tỷ VNĐ (1/1/2017) xuống còn 115.69 tỷ VNĐ (31/12/2017). Không có nợ vay ngắn hạn tại thời điểm cuối năm. Nợ dài hạn chỉ 30 triệu VNĐ. Công ty có vị thế nợ rất thấp, áp lực trả nợ không đáng kể.', 'Hàng tồn kho giảm từ 6.83 tỷ VNĐ xuống còn 5.54 tỷ VNĐ, chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng. Xây dựng cơ bản dở dang đã được hoàn thành và chuyển sang tài sản cố định, không có ứ đọng. Rủi ro tồn kho thấp.', 6, 'Công ty có tình hình tài khỏe mạnh với nợ vay rất thấp và dòng tiền kinh doanh dương lớn. Tuy nhiên, lợi nhuận sau thuế giảm 38% so với năm trước do giá vốn tăng mạnh. Công ty đầu tư lớn vào hệ sinh thái công ty con và liên kết, cho vay nội bộ lớn không lãi suất, tạo ra rủi ro tập trung và quản trị. Điểm sáng là tỷ suất lợi nhuận gộp vẫn ở mức tốt (28%) và công ty trả cổ tức đều đặn.'),
('VSC_2015_consolidated', 'VSC', 2015, 'consolidated', 'Doanh nghiệp có phát sinh giao dịch lớn với các công ty liên kết, đặc biệt là giao dịch sử dụng dịch vụ lên tới 70 tỷ VND với Công ty Cổ phần Cảng dịch vụ Dầu khí Đình Vũ. Các khoản phải trả cho công ty liên kết này không chịu lãi, không có đảm bảo và phải trả khi được yêu cầu, tạo ra rủi ro về khả năng thanh toán và tính minh bạch.', 'Áp lực nợ vay dài hạn tăng mạnh từ 9 tỷ lên hơn 417 tỷ VND, chủ yếu là khoản vay 405 tỷ VND để đầu tư xây dựng cầu cảng. Các khoản vay được đảm bảo bằng tài sản cố định lớn. Công ty có tỷ lệ đòn bẩy tài chính tăng cao, tiềm ẩn rủi ro về khả năng trả nợ nếu dòng tiền kinh doanh bị suy giảm.', 'Hàng tồn kho tăng nhẹ, chủ yếu là nguyên vật liệu, không có dự phòng giảm giá. Dự án xây dựng cầu cảng giai đoạn 2 tại Cảng Xanh VIP có quy mô đầu tư lớn (gần 78 tỷ VND) đang trong quá trình triển khai, cần giám sát tiến độ và hiệu quả đầu tư.', 4, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng tốt với lợi nhuận gộp biên cao (khoảng 40%) và lợi nhuận sau thuế tăng. Tuy nhiên, rủi ro tài chính tăng lên đáng kể do mở rộng quy mô nợ vay dài hạn để đầu tư xây dựng. Giao dịch với các bên liên quan, đặc biệt là công ty liên kết, cần được theo dõi chặt chẽ. Điểm sáng là dòng tiền từ hoạt động kinh doanh mạnh và khả năng sinh lời ổn định.'),
('VSC_2015_parent', 'VSC', 2015, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con và liên kết, bao gồm cho vay không lãi suất, thuê tài sản, mua bán dịch vụ nội bộ. Các giao dịch này là một phần của cấu trúc tập đoàn, chưa phát hiện dấu hiệu bất thường rõ ràng như giao dịch giá chuyển nhượng chênh lệch lớn hay công ty ''sân sau'' của ban lãnh đạo.', 'Áp lực nợ vay thấp. Nợ vay chủ yếu là khoản vay dài hạn USD với lãi suất cố định 4%/năm, đáo hạn năm 2017. Một phần nợ vay dài hạn đã được chuyển thành nợ ngắn hạn. Tài sản thế chấp là tài sản cố định hữu hình, giá trị còn lại đủ để bảo đảm cho khoản vay. Khả năng thanh toán nợ vay được hỗ trợ bởi dòng tiền hoạt động kinh doanh mạnh.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là nguyên vật liệu và hàng hóa, giá trị không lớn và không có dự phòng giảm giá. Không ghi nhận các dự án xây dựng dở dang có giá trị lớn.', 5, 'Tình hình tài chính của doanh nghiệp khỏe mạnh. Tốc độ tăng trưởng doanh thu và lợi nhuận tốt. Dòng tiền từ hoạt động kinh doanh dồi dào. Nợ vay ở mức an toàn, có tài sản đảm bảo. Quản trị công ty có mức độ rủi ro trung bình do có nhiều giao dịch nội bộ trong tập đoàn, tuy nhiên chưa phát hiện sai phạm lớn. Triển vọng đầu tư tích cực.'),
('VSA_2025_consolidated', 'VSA', 2025, 'consolidated', 'Tập đoàn có mạng lưới giao dịch bên liên quan rất rộng, chủ yếu là các đơn vị trong hệ thống Tổng Công ty Hàng Hải Việt Nam (VIMC) bao gồm nhiều cảng, công ty vận tải và logistics. Doanh thu với bên liên quan đạt khoảng 9,8 tỷ VNĐ (chiếm chưa đến 1% doanh thu), mua hàng/dịch vụ với bên liên quan khoảng 22 tỷ VNĐ. Các khoản phải thu từ Công ty Cổ phần Vinalines Nha Trang (125 triệu VNĐ) được trích lập dự phòng 100%. Có khoản phải trả chờ xử lý lớn với Shanghai Zhonggu Logistics Co., Ltd (9,3 tỷ VNĐ) tồn đọng nhiều năm do chênh lệch cách tính thuế. Tổng thể, chưa phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá lớn, tuy nhiên mạng lưới liên quan phức tạp đòi hỏi sự giám sát chặt chẽ.', 'Áp lực nợ vay của doanh nghiệp rất thấp. Tổng nợ vay chỉ có 1,67 tỷ VNĐ nợ ngắn hạn (vay BIDV chi nhánh Đông Hải Phòng), không có nợ vay dài hạn. Tỷ lệ nợ vay/tổng tài sản chỉ khoảng 0,26% - mức cực kỳ an toàn. Khoản vay được thế chấp bằng xe đầu kéo và sơ mi rơ moóc. Doanh nghiệp có lượng tiền mặt dồi dào (229 tỷ VNĐ) và đầu tư tài chính ngắn hạn (66 tỷ VNĐ) nên hoàn toàn có khả năng thanh toán nợ vay. Tuy nhiên, Công ty có nghĩa vụ trả cổ tức lớn (21,1 tỷ VNĐ trong năm 2025).', 'Rủi ro tồn kho và dự án dở dang thấp. Chi phí xây dựng cơ bản dở dang chỉ còn 212 triệu VNĐ, giảm so với 358 triệu VNĐ đầu năm, chủ yếu là chi phí xây dựng tường rào kho bãi và chi phí khác. Doanh nghiệp không có hàng tồn kho (hàng hóa, nguyên vật liệu) đáng kể trên bảng cân đối kế toán. Mô hình kinh doanh dịch vụ hàng hải nên không chịu rủi ro tồn kho như doanh nghiệp sản xuất hay bất động sản.', 3, 'Công ty Cổ phần Đại lý Hàng hải Việt Nam (VOSA) là doanh nghiệp dịch vụ hàng hải có quy mô trung bình, thuộc hệ thống Tổng Công ty Hàng Hải Việt Nam (VIMC) với vốn chủ sở hữu 339 tỷ VNĐ, tổng tài sản 640 tỷ VNĐ. Năm 2025, doanh thu thuần đạt 1.080 tỷ VNĐ (giảm nhẹ 2% so với năm 2024), lợi nhuận sau thuế đạt 23,7 tỷ VNĐ (tăng 8,3% so với năm trước). Tỷ suất lợi nhuận gộp khoảng 9%, phản ánh đặc thù ngành dịch vụ thương mại biên lợi nhuận mỏng. Điểm mạnh: tình hình tài chính lành mạnh với tỷ lệ nợ vay cực thấp (0,26%), tiền mặt dồi dào (229 tỷ VNĐ), không có vấn đề về hoạt động liên tục. Điểm cần lưu ý: doanh thu giảm nhẹ, lợi nhuận khác bị lỗ 2,1 tỷ VNĐ, một số khoản phải thu từ bên liên quan có rủi ro. Công ty đang thực hiện tái cấu trúc bằng cách chuyển đổi chi nhánh thành công ty con độc lập (Vitamas, Northfreight, VOSA Sài Gòn). Triển vọng trung hạn ổn định nhờ vị thế trong ngành đại lý hàng hải và hệ sinh thái VIMC.'),
('VSA_2017_consolidated', 'VSA', 2017, 'consolidated', 'Công ty có mạng lưới giao dịch với các bên liên quan rộng rãi, bao gồm công ty mẹ (Tổng Công ty Hàng hải Việt Nam), nhiều công ty con và công ty liên kết trong lĩnh vực hàng hải, cảng biển. Giao dịch bao gồm doanh thu dịch vụ, chi phí thuê, cổ tức và góp vốn. Mặc dù không có bằng chứng giao dịch bất thường rõ ràng (cho vay không lãi suất, mua bán chênh lệch lớn), nhưng mức độ liên kết cao đòi hỏi sự giám sát chặt chẽ để đảm bảo tính minh bạch và công bằng.', 'Nợ vay tương đối thấp với 96 triệu VND nợ ngắn hạn và 344 triệu VND nợ dài hạn (sau khi xóa khoản vay lớn không lãi suất). Khoản vay ngân hàng có lãi suất 8.86%/năm và được đảm bảo bằng tài sản cố định. Áp lực trả nợ thấp, khả năng thanh toán tốt, dòng tiền kinh doanh mạnh.', 'Hàng tồn kho rất thấp (dưới 1 triệu VND). Rủi ro chính nằm ở Xây dựng cơ bản dở dang trị giá ~75,6 tỷ VND, chủ yếu là dự án bất động sản tại Bến Vân Đồn. Dự án này đã treo nhiều năm, tiềm ẩn rủi ro về tiến độ, vốn và thị trường bất động sản.', 5, 'Công ty có sức khỏe tài chính ổn định, tỷ suất lợi nhuận gộp ~10.6%, dòng tiền kinh doanh hoạt động mạnh (26 tỷ VND). Mức nợ thấp, thanh khoản tốt với tiền và tương đương tiền ~155 tỷ VND. Rủi ro lớn nhất là khoản đầu tư vào dự án xây dựng dở dang lớn và mạng lưới giao dịch bên liên quan phức tạp. Triển vọng trung bình, phụ thuộc vào kết quả thoái vốn tại công ty con bất động sản và hiệu quả hoạt động kinh doanh dịch vụ hàng hải cốt lõi.'),
('VSA_2025_parent', 'VSA', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan trong cùng Tập đoàn Hàng hải Việt Nam (VIMC), bao gồm doanh thu dịch vụ, mua nguyên vật liệu và doanh thu hoạt động tài chính (cho vay, lãi đầu tư). Tổng giá trị giao dịch lớn, tuy nhiên các giao dịch này được thực hiện theo giá thị trường và có thuyết minh rõ ràng, chưa phát hiện dấu hiệu bất thường đáng ngờ.', 'Công ty không có nợ vay ngân hàng (chi phí lãi vay bằng 0). Nợ chủ yếu là phải trả người bán, thuế và các khoản phải trả khác mang tính chất thương mại. Áp lực nợ ngắn hạn thấp, khả năng thanh toán tốt.', 'Công ty không có hàng tồn kho (nguyên vật liệu, thành phẩm). Chỉ có một khoản chi phí xây dựng cơ bản dở dang nhỏ (212 triệu VND). Rủi ro tồn kho và dự án dở dang không đáng kể.', 4, 'Công ty hoạt động ổn định trong lĩnh vực dịch vụ và thương mại hàng hải. Doanh thu năm 2025 giảm nhẹ so với 2024 nhưng lợi nhuận sau thuế tăng 22% nhờ cải thiện biên lợi nhuận gộp và giảm chi phí tài chính. Tình hình tài chính lành mạnh: tỷ lệ nợ thấp, thanh khoản tốt (tiền mặt và tương đương tiền đạt 184,6 tỷ VND). Công ty có mạng lưới công ty con, liên kết rộng trong ngành. Rủi ro chính tập trung vào sự phụ thuộc vào Tập đoàn mẹ và các đơn vị thành viên.'),
('VSA_2017_parent', 'VSA', 2017, 'parent', 'Công ty có nhiều giao dịch với công ty mẹ và các công ty con/liên kết trong hệ sinh thái Vinalines. Các giao dịch bao gồm cho thuê văn phòng, cung cấp dịch vụ logistics, trả phí dịch vụ và chia cổ tức. Mối quan hệ kinh doanh mật thiết này là đặc trưng của nhóm doanh nghiệp nhà nước, tuy nhiên không phát hiện giao dịch bất thường rõ ràng (như cho vay không lãi suất với đối tượng ngoài hệ thống hay mua bán chênh lệch giá lớn). Rủi ro tập trung ở sự phụ thuộc lẫn nhau trong chuỗi dịch vụ hàng hải.', 'Tổng nợ vay không đáng kể so với tổng tài sản. Nợ ngắn hạn chỉ có 96 tỷ VND (khoản vay dài hạn đáo hạn). Nợ dài hạn còn 344 tỷ VND từ một khoản vay ngân hàng có thế chấp tài sản và lãi suất hợp lý (8.68%/năm). Áp lực trả nợ rất thấp, khả năng thanh toán tốt.', 'Hàng tồn kho không đáng kể (877,500 VND). Các dự án xây dựng dở dang có giá trị nhỏ và đang trong quá trình triển khai, không có dấu hiệu ứ đọng lớn.', 4, 'Công ty Cổ phần Đại lý Hàng hải Việt Nam (VSA) có tình hình tài chính lành mạnh. Tỷ suất lợi nhuận gộp ổn định khoảng 10.6%. Nợ vay rất thấp, chủ yếu hoạt động bằng vốn chủ sở hữu và vốn lưu động. Công ty có dòng tiền kinh doanh dương mạnh và thanh khoản tốt với tiền và tương đương tiền hơn 151 tỷ VND. Tuy nhiên, doanh thu và lợi nhuận có xu hướng giảm nhẹ so với năm trước. Công ty nằm trong hệ thống Vinalines nên có sự hỗ trợ và liên kết kinh doanh nội bộ.'),
('VSA_2024_consolidated', 'VSA', 2024, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan trong Tập đoàn (Tổng công ty Hàng hải Việt Nam - CTCP và các công ty con). Các giao dịch chủ yếu là doanh thu bán dịch vụ và mua hàng hóa/dịch vụ. Có khoản phải thu từ Công ty Cổ phần Vinalines Nha Trang đã lập dự phòng 100% (125.410.683 VND) cho thấy rủi ro thu hồi. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là phải trả người bán, thuế và các khoản phải nộp Nhà nước, chi phí phải trả. Có khoản phải trả khác lớn (hơn 100 tỷ) bao gồm tiền ký quỹ, tiền nhận để trả hộ cho các hãng tàu - đây là tiền giữ hộ, không phải nợ thực sự. Áp lực nợ thấp, khả năng thanh toán tốt.', 'Công ty chỉ có chi phí xây dựng cơ bản dở dang giá trị nhỏ (358 triệu VND) và không có hàng tồn kho vật chất. Rủi ro tồn kho thấp.', 4, 'Công ty hoạt động trong lĩnh vực dịch vụ hàng hải, doanh thu thuần năm 2024 đạt hơn 1.100 tỷ VND, lợi nhuận sau thuế 21,9 tỷ VND. Cơ cấu tài sản lành mạnh, không có nợ vay ngân hàng, dòng tiền từ hoạt động kinh doanh dương mạnh (76,6 tỷ VND). Công ty có mối quan hệ chặt chẽ với Tập đoàn mẹ và các công ty con, điều này tạo ra both cơ hội và rủi ro phụ thuộc. Triển vọng đầu tư ổn định, phù hợp với nhà đầu tư tìm kiếm cổ tức ổn định và mức độ rủi ro thấp.'),
('VSA_2024_parent', 'VSA', 2024, 'parent', 'Giao dịch với các bên liên quan chủ yếu với các công ty trong cùng Tập đoàn Hàng hải Việt Nam, không phát hiện giao dịch bất thường như cho vay không lãi suất, mua bán chênh lệch lớn với các công ty sân sau.', 'Công ty chủ yếu nợ phải trả người bán và các khoản phải trả khác, không có nợ vay ngân hàng, áp lực nợ thấp và không có tài sản thế chấp nổi bật.', 'Công ty không có hàng tồn kho lớn, chỉ có chi phí xây dựng dở dang nhỏ, không bị ứ đọng, rủi ro thấp.', 2, 'Tình hình tài chính ổn định với lượng tiền mặt lớn và đầu tư dài hạn, nhưng biên lợi nhuận gộp giảm so với năm trước do doanh thu sụt giảm. Công ty có quản trị tốt và triển vọng trung bình trong ngành hàng hải.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VSA_2015_consolidated', 'VSA', 2015, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu với công ty mẹ và các công ty liên kết, bao gồm chia cổ tức, doanh thu và chi phí dịch vụ. Không có dấu hiệu bất thường, nhưng cần theo dõi các tranh chấp pháp lý như với Manuchar Hong Kong Limited.', 'Nợ dài hạn không lãi suất, đáo hạn trong dài hạn, áp lực nợ thấp. Tuy nhiên, có khoản nợ tiềm tàng từ tranh chấp có thể tăng rủi ro tài chính.', 'Tồn kho thấp, nhưng dự án xây dựng dở dang lớn, có thể rủi ro chậm tiến độ và tăng chi phí.', 6, 'Công ty có lợi nhuận ổn định nhưng giảm nhẹ so với năm trước. Cơ cấu tài sản với bất động sản đầu tư và xây dựng dở dang chiếm tỷ trọng lớn. Nợ vay không lãi suất là điểm tích cực, nhưng rủi ro từ tranh chấp và dự án đầu tư cần được giám sát.'),
('VSA_2015_parent', 'VSA', 2015, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm công ty mẹ và các công ty thành viên. Các giao dịch chủ yếu là chia cổ tức, cho thuê, góp vốn và thanh toán dịch vụ. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Nợ vay dài hạn chỉ có 2 khoản không lãi suất, đáo hạn 2019 và 2023, áp lực trả nợ thấp. Nợ ngắn hạn lớn (260,508,772,264 VND) chủ yếu là phải trả người bán và thuế, phản ánh hoạt động kinh doanh thông thường.', 'Hàng tồn kho có giá trị rất nhỏ (175,500 VND). Xây dựng cơ bản dở dang còn 305,518,229 VND là dự án nhà văn phòng Vitamas, không có dấu hiệu ứ đọng.', 3, 'Công ty hoạt động ổn định trong lĩnh vực đại lý hàng hải, doanh thu và lợi nhuận tăng trưởng. Tài sản lớn, nợ vay thấp, nhưng có tranh chấp kiện tụng với Manuchar Hong Kong Limited và Công ty TNHH Manuchar Việt Nam về khoản nợ tiền hàng năm 2008, tuy nhiên số tiền dự kiến thanh toán đã được ghi nhận là 8,342,091,909 VND. Triển vọng trung bình, cần theo dõi tiến trình hòa giải.'),
('VSA_2016_parent', 'VSA', 2016, 'parent', 'Công ty có nhiều giao dịch với bên liên quan bao gồm công ty mẹ, công ty con và công ty liên kết, chủ yếu liên quan đến chia cổ tức, thuê văn phòng và dịch vụ vận tải. Các giao dịch này có vẻ là giao dịch kinh doanh thông thường, không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất hoặc mua bán chênh lệch lớn.', 'Áp lực nợ vay thấp vì công ty chỉ có một khoản vay dài hạn không lãi suất từ Luen Wah Trading Co., Ltd. đáo hạn năm 2023, và không có nợ ngắn hạn. Khả năng thanh toán nợ được đảm bảo.', 'Hàng tồn kho bằng 0, không có rủi ro tồn kho. Dự án xây dựng dở dang là các dự án văn phòng với giá trị nhỏ, không có dấu hiệu ứ đọng.', 5, 'Công ty có tình hình tài chính ổn định với lợi nhuận gộp cao, chi phí khấu hao đáng kể và thu nhập từ đầu tư. Nợ vay thấp, dòng tiền từ hoạt động kinh doanh dương, nhưng dòng tiền đầu tư và tài chính âm do chi phí mua sắm tài sản và chia cổ tức. Các giao dịch với bên liên quan không phức tạp, điểm rủi ro quản trị trung bình. Triển vọng đầu tư khả quan trong ngắn hạn.'),
('VSA_2016_consolidated', 'VSA', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu mang tính thương mại thông thường (cho thuê văn phòng, cung cấp dịch vụ hàng hải, cảng biển). Tổng Công ty Hàng hải Việt Nam (công ty mẹ) phát sinh các khoản chi phí thuê, điện và dịch vụ. Công ty con và công ty liên kết của công ty mẹ (hệ sinh thái Vinalines) có nhiều giao dịch dịch vụ hàng hải. Tuy nhiên, Công ty TNHH China Shipping Việt Nam là liên doanh đã bị giải thể theo nghị quyết HĐQT năm 2016, Công ty đã lập dự phòng cho phần lỗ gánh chịu, khoản đầu tư giảm mạnh từ 9,47 tỷ xuống 414 triệu VND. Nhìn chung, giao dịch bên liên quan không có dấu hiệu bất thường nghiêm trọng nhưng cấu trúc tập đoàn phức tạp với nhiều công ty con/liên kết thuộc hệ sinh thái Vinalines.', 'Áp lực nợ vay thấp. Tổng nợ vay chỉ khoảng 6,6 tỷ VND (dài hạn, vay từ Luen Wah Trading Co., Ltd. Hong Kong không lãi suất đáo hạn 2023), chiếm ~1% tổng tài sản. Nợ ngắn hạn chủ yếu là phải trả người bán và các khoản trả hộ cho hãng tàu (đặc trưng ngành logistics). Vốn chủ sở hữu 351 tỷ VND chiếm 56,8% tổng tài sản, phản ánh cơ cấu vốn lành mạnh. Công ty không có chi phí lãi vay trong năm 2016. Dòng tiền hoạt động kinh doanh dương 11 tỷ VND (cải thiện mạnh so với -27 tỷ năm 2015).', 'Hàng tồn kho không đáng kể (chỉ 175.500 VND đầu năm, đã xóa sổ hết). Tuy nhiên, xây dựng cơ bản dở dang chiếm 75,5 tỷ VND (~12,2% tổng tài sản), trong đó dự án Bến Vân Đồn chiếm 75,2 tỷ VND. Dự án này đã tồn tại nhiều năm và chưa hoàn thành, tiềm ẩn rủi ro ứ đọng vốn và chậm tiến độ. Giá trị xây dựng dở dang gần như không giảm so với đầu năm.', 5, 'Đại lý Hàng hải Việt Nam (VSA) có nền tảng tài chính vững chắc với tỷ lệ nợ thấp (dưới 1% nợ vay/tổng tài sản), vốn chủ sở hữu chiếm 56,8% và biên lợi nhuận gộp ổn định ~10,6%. Tuy nhiên, doanh thu đi ngang và lợi nhuận sau thuế giảm 9,3% (từ 48,9 tỷ xuống 44,3 tỷ VND) do lỗ từ liên doanh China Shipping (-4,7 tỷ) và giảm doanh thu tài chính. Điểm sáng là dòng tiền kinh doanh cải thiện mạnh, chi phí lãi vay bằng 0, và Công ty nhận khoản đền bù 22 tỷ từ Công ty An Phú. Rủi ro chính là dự án Bến Vân Đồn 75 tỷ dở dang kéo dài nhiều năm, và cấu trúc tập đoàn phức tạp với nhiều giao dịch nội bộ hệ sinh thái Vinalines. Lãi cơ bản trên cổ phiếu giảm từ 3.753 xuống 3.461 VND.'),
('VRG_2025_consolidated', 'VRG', 2025, 'consolidated', 'Doanh nghiệp có một số giao dịch với các bên liên quan đáng lưu ý: (1) Khoản tạm ứng/phải thu cá nhân cho các thành viên ban lãnh đạo (ông Bùi Gia Hưng - Phó TGĐ: 3,53 tỷ VNĐ; ông Nguyễn Đình Đức - Trưởng Ban KS: 3,36 tỷ VNĐ; bà Phạm Thị Tuyết - Thành viên HĐQT: 2,35 tỷ VNĐ), tổng cộng khoảng 9,24 tỷ VNĐ, không rõ lãi suất và thời hạn trả; (2) Khoản phải thu lớn 31,79 tỷ VNĐ từ Công ty TNHH Nice Ceramic (không phải bên liên quan trực tiếp) đã phải trích lập dự phòng 27,39 tỷ VNĐ, liên quan tranh chấp hợp đồng thuê đất kéo dài từ 2016, đã có bản án phúc thẩm có hiệu lực buộc Nice Ceramic thanh toán 45,74 tỷ VNĐ nhưng chưa thu hồi được; (3) Tập đoàn Công nghiệp Cao su Việt Nam là cổ đông lớn (15,09%) - mối quan hệ tập đoàn mẹ-con tiềm ẩn rủi ro giao dịch nội bộ.', 'Doanh nghiệp không có nợ vay ngân hàng (không có dòng tiền chi trả lãi vay trong Báo cáo lưu chuyển tiền tệ). Cơ cấu nợ chủ yếu là chi phí phải trả dài hạn (268,54 tỷ VNĐ - phần giá vốn hạ tầng KCN chưa quyết toán) và doanh thu chưa thực hiện dài hạn (259,51 tỷ VNĐ). Nợ phải trả ngắn hạn khá nhỏ (61,91 tỷ VNĐ). Công ty có vị thế tiền mặt mạnh với 159,20 tỷ VNĐ tiền và tương đương tiền (trong đó 125,70 tỷ VNĐ tiền gửi có kỳ hạn không quá 3 tháng). Không có tài sản cố định nào dùng để thế chấp đảm bảo khoản vay. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Hàng tồn kho rất nhỏ (chỉ 140,82 triệu VNĐ, chủ yếu là nguyên vật liệu và công cụ dụng cụ), không có dự phòng giảm giá. Rủi ro tồn kho không đáng kể. Tuy nhiên, dự án xây dựng cơ bản dở dang (KCN Cộng Hòa) có giá trị lớn 163,47 tỷ VNĐ, đây là dự án trọng điểm với tổng mức đầu tư hơn 1.250 tỷ đồng, đã được đưa một phần vào khai thác nhưng vẫn đang tiếp tục xây dựng hạ tầng kỹ thuật. Rủi ro tập trung vào tiến độ và hiệu quả khai thác dự án bất động sản công nghiệp.', 5, 'Công ty CP Phát triển Đô thị và KCN Cao su Việt Nam (VRG) hoạt động trong lĩnh vực đầu tư hạ tầng khu công nghiệp, với tài sản chủ yếu là bất động sản đầu tư (231,24 tỷ VNĐ) và xây dựng cơ bản dở dang (163,47 tỷ VNĐ) thuộc dự án KCN Cộng Hòa. Doanh thu năm 2025 đạt 133,95 tỷ VNĐ, lợi nhuận sau thuế 36,00 tỷ VNĐ (giảm 38,6% so với năm 2024 do năm 2024 có điều chỉnh giảm giá vốn). Tỷ suất lợi nhuận gộp cao (61,8%). Điểm mạnh: Không có nợ vay tài chính, tiền mặt dồi dào (159,20 tỷ VNĐ), dòng tiền hoạt động đầu tư dương lớn (126,85 tỷ VNĐ nhờ thu 150 tỷ VNĐ từ tiền gửi đáo hạn). Điểm rủi ro: (1) Khoản phải thu lớn từ Nice Ceramic (31,79 tỷ VNĐ) đã trích lập dự phòng 86% và đang trong quá trình thi hành án; (2) Tạm ứng cho cá nhân ban lãnh đạo gần 9,24 tỷ VNĐ; (3) Dự án KCN Cộng Hòa quy mô lớn đang trong giai đoạn đầu tư, cần theo dõi tiến độ và khả năng lấp đầy. Công ty chia cổ tức cao (90,63 tỷ VNĐ trong năm) cho thấy chính sách chi trả cổ đông hào phóng. Tổng thể, doanh nghiệp có sức khỏe tài chính ổn định, không có đòn bẩy nợ, nhưng phụ thuộc lớn vào tiến độ dự án KCN Cộng Hòa và hiệu quả thu hồi công nợ Nice Ceramic.'),
('VRG_2024_consolidated', 'VRG', 2024, 'consolidated', 'Doanh nghiệp có một số giao dịch với bên liên quan đáng lưu ý: (1) Khoản phải thu ngắn hạn từ cá nhân là Phó Tổng Giám đốc Bùi Gia Hưng lên tới 3,54 tỷ VNĐ, là khoản phải thu cá nhân lớn nhất trong số các thành viên quản lý chủ chốt; (2) Công ty TNHH Nice Ceramic nợ 29,1 tỷ VNĐ (tiền thuê đất từ 2016) đã quá hạn nhiều năm, tỷ lệ dự phòng trích lập 83.6%, công ty đã khởi kiện ra tòa; (3) Đầu tư góp vốn vào Công ty CP Tư vấn xây dựng Đô thị và KCN Cao su Việt Nam đã ngừng hoạt động từ 2018 nhưng chưa đóng mã số thuế, giá trị 500 triệu đã trích lập dự phòng toàn bộ. Tuy nhiên, giao dịch với bên liên quan không có dấu hiệu bất thường nghiêm trọng như cho vay không lãi suất hay mua bán chênh lệch giá bất thường.', 'Công ty không có nợ vay ngân hàng truyền thống (không phát sinh chi phí lãi vay trong năm 2024). Nợ chủ yếu là phải trả nhà cung cấp ngắn hạn (17,1 tỷ VNĐ) và chi phí phải trả dài hạn liên quan đến giá vốn hạ tầng KCN (265 tỷ VNĐ) và doanh thu chưa thực hiện từ cho thuê KCN (267,8 tỷ VNĐ). Tiền và tương đương tiền cuối năm đạt 126,8 tỷ VNĐ (trong đó tiền gửi có kỳ hạn 113,4 tỷ VNĐ). Công ty có bảng cân đối lành mạnh với tỷ lệ nợ/vốn chủ sở hữu = 1.52, thanh khoản dồi dào, không có áp lực nợ vay ngân hàng.', 'Hàng tồn kho rất nhỏ (chỉ 159,7 triệu VNĐ), không đáng kể. Rủi ro chính nằm ở chi phí xây dựng cơ bản dở dang dự án KCN Cộng Hòa với giá trị 330,3 tỷ VNĐ. Dự án đã được điều chỉnh tổng mức đầu tư từ 834 tỷ lên hơn 1.250 tỷ đồng và gia hạn tiến độ. Công ty đã đưa một phần vào khai thác nhưng phần lớn vẫn đang xây dựng, do đó rủi ro ứ đọng vốn đầu tư là đáng kể nếu tiến độ thi công bị chậm trễ hoặc tỷ lệ lấp đầy KCN không đạt kỳ vọng.', 4, 'Công ty CP Phát triển Đô thị và KCN Cao su Việt Nam (VRG) là doanh nghiệp kinh doanh hạ tầng khu công nghiệp tại Hải Dương. Điểm mạnh: biên lợi nhuận gộp cực cao (92.5% năm 2024), không có nợ vay ngân hàng, thanh khoản tốt, tỷ lệ chi trả cổ tức hấp dẫn (hơn 98 tỷ VNĐ năm 2024). Điểm yếu: Doanh thu và lợi nhuận giảm mạnh so với năm 2023 (LNST giảm 68.5%) do năm 2023 ghi nhận doanh thu một lần từ nhiều hợp đồng thuê đất lớn, trong khi năm 2024 chỉ ký mới 1 hợp đồng. Rủi ro lớn nhất là khoản phải thu từ Công ty TNHH Nice Ceramic (29,1 tỷ VNĐ) đã trích lập dự phòng 83.6% và đang trong quá trình kiện tụng. Dự án KCN Cộng Hòa với tổng mức đầu tư hơn 1.250 tỷ đồng đòi hỏi vốn đầu tư lớn trong dài hạn, tỷ lệ lấp đầy sẽ quyết định triển vọng doanh nghiệp.'),
('VRG_2021_consolidated', 'VRG', 2021, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là thù lao cho Hội đồng quản trị, Ban kiểm soát và Ban Tổng Giám đốc theo nghị quyết Đại hội đồng cổ đông, không phát sinh giao dịch bất thường. Các bên liên quan khác không có giao dịch và số dư công nợ.', 'Công ty không có nợ vay (vay và nợ thuê tài chính ngắn hạn, dài hạn đều bằng 0). Nợ phải trả chủ yếu là phải trả người bán ngắn hạn và chi phí phải trả dài hạn, áp lực trả nợ thấp.', 'Công ty không có hàng tồn kho (số dư bằng 0). Rủi ro tập trung ở chi phí xây dựng cơ bản dở dang cho dự án Khu Công nghiệp Cộng Hòa, nếu dự án chậm tiến độ hoặc kinh doanh bất động sản khó khăn có thể ảnh hưởng đến dòng tiền.', 5, 'Công ty hoạt động trong lĩnh vực đầu tư hạ tầng khu công nghiệp, chịu ảnh hưởng của đại dịch Covid-19 khiến doanh thu và lợi nhuận giảm. Tuy nhiên, công ty không có nợ vay, tài sản chủ yếu là bất động sản đầu tư và xây dựng cơ bản dở dang. Ý kiến kiểm toán ngoại trừ do khoản nợ phải thu của Công ty TNHH Nice Ceramic chưa được đối chiếu, xác nhận, tạo rủi ro tiềm ẩn về thu hồi nợ. Triển vọng phụ thuộc vào khả năng thu hút đầu tư vào khu công nghiệp và giải quyết khoản nợ khó đòi.'),
('VRG_2023_consolidated', 'VRG', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là chi phí lương thưởng cho thành viên HĐQT, Ban Tổng Giám đốc và Ban Kiểm soát, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Công ty không có vay ngân hàng, nợ phải trả chủ yếu là phải trả người bán và chi phí phải trả ngắn hạn, áp lực nợ vay thấp. Dòng tiền từ hoạt động kinh doanh dương mạnh, khả năng thanh toán tốt.', 'Không có hàng tồn kho. Dự án xây dựng cơ bản dở dang (Khu công nghiệp Cộng Hòa) có giá trị lớn, nhưng đang trong quá trình triển khai, rủi ro về tiến độ và chi phí tồn tại nhưng được kiểm soát.', 2, 'Công ty có kết quả kinh doanh tăng trưởng mạnh trong năm 2023 với lợi nhuận sau thuế đạt 186,587,914,737 VND, chủ yếu từ doanh thu cho thuê đất khu công nghiệp. Tình hình tài chính lành mạnh, không có nợ vay, dòng tiền dồi dào. Tuy nhiên, doanh thu tập trung vào dự án bất động sản cụ thể, rủi ro phụ thuộc vào tiến độ dự án và thị trường bất động sản.'),
('VRG_2019_consolidated', 'VRG', 2019, 'consolidated', 'Công ty có giao dịch với thành viên quản lý chủ chốt chủ yếu là tiền lương và tiền thưởng, không phát hiện giao dịch bất thường đáng kể. Các bên liên quan khác là cổ đông nhưng không phát sinh giao dịch.', 'Công ty không có nợ vay ngân hàng hay nợ thuê tài chính. Nợ phải trả chủ yếu là phải trả người bán và doanh thu chưa thực hiện từ cho thuê hạ tầng, áp lực nợ thấp, khả năng thanh toán tốt.', 'Công ty không có hàng tồn kho. Dự án xây dựng cơ bản dở dang (Khu Công nghiệp Cộng Hòa) có giá trị lớn và đang trong quá trình triển khai, cần theo dõi tiến độ và rủi ro chi phí phát sinh.', 5, 'Công ty ghi nhận kết quả kinh doanh tích cực năm 2019 với lợi nhuận tăng mạnh nhờ ghi nhận doanh thu từ cho thuê hạ tầng khu công nghiệp. Tuy nhiên, rủi ro chính bao gồm khoản phải thu từ Công ty TNHH Nice Ceramic chưa được xác nhận và dự án xây dựng dở dang đòi hỏi vốn đầu tư lớn. Công ty không có nợ vay, tài chính ổn định nhưng phụ thuộc vào dòng tiền từ hoạt động kinh doanh.'),
('VRG_2018_consolidated', 'VRG', 2018, 'consolidated', 'Giao dịch với bên liên quan (công ty mẹ) có giá trị nhỏ (66 triệu VND), không có bất thường đáng kể.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán và doanh thu chưa thực hiện, áp lực nợ thấp.', 'Hàng tồn kho ít (85 triệu VND) là hàng tặng, không có rủi ro. Dự án xây dựng dở dang lớn (203 tỷ VND) đang tiến hành, doanh thu nhận trước tăng cho thấy dự án được thị trường đón nhận, nhưng cần theo dõi tiến độ.', 5, 'Công ty hoạt động trong lĩnh vực bất động sản công nghiệp, doanh thu giảm so với năm trước do không có doanh thu chuyển nhượng bất động sản phát sinh một lần. Lợi nhuận giảm do tăng chi phí dự phòng và nhân viên. Tuy nhiên, dòng tiền hoạt động kinh doanh cải thiện mạnh (36.4 tỷ VND). Dự án Khu công nghiệp Cộng Hòa đang xây dựng và đã cho thuê, tạo doanh thu định kỳ. Triển vọng phụ thuộc vào tiến độ dự án và khả năng thu hút nhà đầu tư.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VRG_2017_consolidated', 'VRG', 2017, 'consolidated', 'Giao dịch với công ty mẹ chỉ là thanh toán chi phí nhỏ (131.828.272 VND), không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, rủi ro thấp.', 'Công ty không có vay nợ ngân hàng hay nợ thuê tài chính, nợ chủ yếu là phải trả người bán và doanh thu chưa thực hiện từ cho thuê hạ tầng, áp lực nợ thấp.', 'Không có hàng tồn kho, nhưng dự án xây dựng cơ bản dở dang Khu Công nghiệp Cộng Hòa có tổng mức đầu tư lớn và đang trong quá trình xây dựng, có thể bị chậm tiến độ hoặc phát sinh chi phí, rủi ro trung bình.', 5, 'Công ty đã có sự cải thiện về tài chính trong năm 2017 với lợi nhuận sau thuế 2.851.135.638 VND, chuyển từ lỗ sang lãi, nhưng vẫn còn lỗ lũy kế. Sức khỏe tài chính ổn định nhờ ưu đãi thuê đất và doanh thu từ kinh doanh bất động sản. Triển vọng đầu tư phụ thuộc vào tiến độ và hiệu quả khai thác dự án Khu Công nghiệp Cộng Hòa.'),
('VRE_2025_consolidated', 'VRE', 2025, 'consolidated', 'Doanh nghiệp có giao dịch lớn và phức tạp với các bên liên quan thuộc Tập đoàn Vingroup. Các khoản đặt cọc đầu tư/kinh doanh với bên liên quan lên đến hàng nghìn tỷ VNĐ. Doanh thu bán hàng và dịch vụ từ bên liên quan chiếm tỷ trọng đáng kể (khoảng 9.9% tổng doanh thu). Lãi cho vay và đặt cọc từ bên liên quan chiếm phần lớn doanh thu tài chính. Tuy nhiên, các giao dịch này được ghi nhận trong thuyết minh và có lãi suất thương mại (10-12%/năm cho đặt cọc). Rủi ro tập trung vào tính độc lập và giá cả có ưu đãi hay không.', 'Nợ dài hạn tăng mạnh từ 7.382 tỷ lên 7.737 tỷ VNĐ, chủ yếu từ vay hợp vốn dài hạn (6.208 tỷ). Lãi suất vay dao động 7.68-14.02%/năm. Áp lực lãi vay tăng (chi phí lãi vay 628 tỷ năm 2025). Tuy nhiên, Công ty có tài sản đảm bảo lớn (bất động sản đầu tư thế chấp >1.000 tỷ) và tiền mặt mạnh (hơn 4.434 tỷ). Khả năng thanh toán lãi vay từ lợi nhuận hoạt động kinh doanh (lợi nhuận gộp 4.732 tỷ) vẫn đảm bảo.', 'Hàng tồn kho giảm từ 295 tỷ xuống 236 tỷ, chủ yếu là thành phẩm bất động sản (nhà phố, nhà ở xã hội). Dự án xây dựng dở dang giảm mạnh từ 801 tỷ xuống 267 tỷ, cho thấy tiến độ giải ngân và triển khai dự án. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho thấp do thị trường bất động sản vẫn có nhu cầu.', 5, 'Vincom Retail có kết quả kinh doanh tăng trưởng tốt (LNTST 6.446 tỷ, tăng 57%), hoạt động cho thuê đóng góp doanh thu chính. Công ty có vị thế tiền mặt mạnh và tỷ lệ nợ trên vốn chủ sở hữu ở mức an toàn (0.27). Rủi ro chính đến từ giao dịch với bên liên quan tập đoàn Vingroup và áp lực lãi vay tăng. Triển vọng trung hạn tích cực nhờ danh mục bất động sản đầu tư lớn và dòng tiền cho thuê ổn định.'),
('VRG_2016_consolidated', 'VRG', 2016, 'consolidated', 'Giao dịch với bên liên quan chỉ có Tập đoàn Công nghiệp Cao su Việt Nam với số tiền nhỏ 125 triệu VNĐ, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp không có nợ vay ngân hàng, các khoản nợ phải trả chủ yếu là doanh thu chưa thực hiện từ tiền thuê đất và chi phí phải trả, áp lực nợ vay thấp.', 'Chi phí xây dựng cơ bản dở dang lớn 156,5 tỷ VNĐ, dự án hạ tầng KCN Cộng Hòa đang trong giai đoạn xây dựng, tiến độ gia hạn đến 2017, có rủi ro chậm trễ và ứ đọng vốn.', 4, 'Công ty đang trong giai đoạn đầu tư xây dựng hạ tầng khu công nghiệp, chưa phát sinh doanh thu lớn, lỗ lũy kế tăng, nhưng không có nợ vay ngân hàng. Triển vọng phụ thuộc vào tiến độ dự án và thu hút nhà đầu tư.'),
('VRG_2015_consolidated', 'VRG', 2015, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là khoản phải thu 125 triệu VND cho Tập đoàn Công nghiệp Cao su Việt Nam, không có lãi suất và không có bảo đảm, rủi ro thấp.', 'Công ty không có nợ vay, các khoản nợ phải trả chủ yếu là phải trả người bán và doanh thu chưa thực hiện, áp lực nợ thấp.', 'Hàng tồn kho bằng không, nhưng chi phí xây dựng cơ bản dở dang cho dự án khu công nghiệp Cộng Hòa lớn, cần giám sát tiến độ và hiệu quả.', 4, 'Công ty đang hoạt động trong lĩnh vực bất động sản khu công nghiệp, có dự án lớn trong quá trình xây dựng. Năm 2015 công ty lỗ ròng 1.48 tỷ VND, nhưng có tiền mặt và tương đương tiền 50.1 tỷ VND. Doanh thu tăng so với năm trước, nhưng giá vốn cao dẫn đến lỗ gộp. Tuy nhiên, doanh thu hoạt động tài chính từ lãi tiền gửi bù đắp một phần. Công ty có khả năng thanh toán các khoản nợ ngắn hạn, nhưng triển vọng phụ thuộc vào tiến độ dự án khu công nghiệp và thị trường bất động sản.'),
('VRE_2025_parent', 'VRE', 2025, 'parent', 'Doanh nghiệp có giao dịch lớn với các bên liên quan, bao gồm doanh thu, chi phí, đặt cọc và vay, cho thấy sự phụ thuộc cao vào tập đoàn mẹ và công ty con. Cần lưu ý rủi ro về giao dịch không công bằng hoặc lợi ích chồng chéo.', 'Nợ vay tăng đáng kể, đặc biệt nợ dài hạn với lãi suất cố định và thả nổi. Có tài sản đảm bảo nhưng áp lực trả nợ lãi cao, chi phí lãi vay năm nay đạt 875,274 triệu VND. Cần theo dõi khả năng thanh toán.', 'Hàng tồn kho thấp, chỉ 8,682 triệu VND, chủ yếu là bất động sản để bán. Rủi ro tồn kho không cao do quy mô nhỏ và không có dự án dở dang lớn.', 7, 'Công ty có kết quả kinh doanh tốt với lợi nhuận sau thuế tăng mạnh lên 7,185,345 triệu VND, nhưng dòng tiền từ hoạt động kinh doanh âm do thay đổi vốn lưu động. Nợ vay tăng để tài trợ đầu tư dài hạn. Sức khỏe tài chính cơ bản ổn định, nhưng cần kiểm soát rủi ro từ giao dịch bên liên quan và quản lý nợ hiệu quả.'),
('VRE_2024_consolidated', 'VRE', 2024, 'consolidated', 'Doanh nghiệp có giao dịch rất lớn với các bên liên quan, đặc biệt là Tập đoàn Vingroup và các công ty con trong tập đoàn. Các khoản đặt cọc đầu tư và kinh doanh lên đến hàng nghìn tỷ VNĐ, cho vay không rõ lãi suất (trừ nợ thuê tài chính có lãi suất cao). Điều này tiềm ẩn rủi ro về tính độc lập, minh bạch và khả năng xảy ra giao dịch không theo giá thị trường.', 'Tổng nợ phải trả là 13.303.514 triệu VNĐ, trong đó nợ ngắn hạn 5.920.740 triệu và nợ dài hạn 7.382.774 triệu. Công ty có trái phiếu đáo hạn trong năm 2025 và các khoản vay hợp vốn đáo hạn năm 2027. Tài sản thế chấp chính là bất động sản đầu tư và tài sản cố định. Áp lực trả nợ ngắn hạn và trung hạn khá lớn.', 'Hàng tồn kho giảm mạnh từ 639.957 triệu xuống 295.010 triệu, chủ yếu là thành phẩm bất động sản đã giảm. Chi phí xây dựng cơ bản dở dang còn 801.624 triệu, tập trung vào một số dự án. Rủi ro tồn kho dở dang không quá cao nhưng vẫn cần theo dõi tiến độ các dự án.', 7, 'Công ty Vincom Retail có quy mô tài sản lớn, lợi nhuận gộp cao trên 53%, nhưng tập trung vào hoạt động cho thuê bất động sản. Các mối quan hệ giao dịch bên liên quan phức tạp với Tập đoàn Vingroup đặt ra nhiều rủi ro về quản trị và tính công bằng. Nợ vay ở mức trung bình nhưng cần được giám sát kỹ dòng tiền. Điểm rủi ro quản trị ở mức cao (7/10) do giao dịch bên liên quan lớn và phức tạp.'),
('VRE_2023_consolidated', 'VRE', 2023, 'consolidated', 'Doanh nghiệp có quan hệ giao dịch phức tạp và giá trị lớn với Tập đoàn Vingroup (công ty mẹ) và các công ty thành viên. Các khoản đặt cọc cho mục đích đầu tư với các bên liên quan lên tới hàng nghìn tỷ đồng (Vingroup: 4.765 tỷ, Vinhomes: 1.090 tỷ, Đô thị Du lịch Cần Giờ: 1.200 tỷ). Ngoài ra, Công ty cho vay lớn (11.145 tỷ VND) với lãi suất cao (11-12%/năm) cho Công ty Sản xuất và Kinh doanh VinFast. Điều này cho thấy sự phụ thuộc lớn vào tập đoàn và tiềm ẩn rủi ro về tập trung nguồn lực và ưu đãi không minh bạch.', 'Áp lực nợ vay ở mức cao với tổng nợ vay và trái phiếu khoảng 3.935 tỷ VND. Lãi suất nợ vay ở mức cao (9,78%-11,43%/năm đối với trái phiếu, 9,85%-9,91%/năm đối với vay ngắn hạn). Tài sản thế chấp chính là bất động sản đầu tư (các trung tâm thương mại) và tài sản cố định. Công ty có dòng tiền hoạt động kinh doanh dương mạnh (3.892 tỷ VND năm 2023) giúp bù đắp áp lực lãi vay.', 'Hàng tồn kho bất động sản giảm mạnh từ 1.178 tỷ xuống 640 tỷ VND, chủ yếu do giảm bất động sản để bán đang xây dựng dở dang (từ 1.130 tỷ xuống 621 tỷ). Dự án xây dựng dở dang tăng từ 699 tỷ lên 1.028 tỷ VND với nhiều dự án đang triển khai (Khách sạn Bắc Ninh, Vincom Điện Biên, Quảng Trị, Biên Hòa 2). Rủi ro tồn kho thấp do phần lớn là tài sản cho thuê có dòng tiền ổn định.', 7, 'Công ty có kết quả kinh doanh tăng trưởng mạnh (lợi nhuận sau thuế tăng 59% năm 2023) nhờ doanh thu cho thuê và chuyển nhượng bất động sản tăng. Tuy nhiên, doanh nghiệp phụ thuộc nhiều vào giao dịch với bên liên quan trong Tập đoàn Vingroup, với các khoản đặt cọc đầu tư lớn và cho vay lãi suất cao. Nợ vay có chi phí lãi suất cao nhưng được hỗ trợ bởi dòng tiền hoạt động kinh doanh mạnh. Tài sản chủ yếu là bất động sản đầu tư có giá trị lớn nhưng thanh khoản thấp. Điểm rủi ro quản trị ở mức 7/10 do cấu trúc tập đoàn phức tạp và giao dịch liên quan chồng chéo.'),
('VRE_2024_parent', 'VRE', 2024, 'parent', 'Công ty có giao dịch lớn với các bên liên quan, bao gồm công ty mẹ và công ty trong cùng tập đoàn. Các giao dịch bao gồm cho thuê, mua bán hàng hóa, dịch vụ và đặt cọc đầu tư. Mặc dù giao dịch được thực hiện theo giá thị trường và có sự phê duyệt, nhưng khối lượng lớn và sự phụ thuộc vào Tập đoàn Vingroup có thể gây rủi ro nếu có xung đột lợi ích hoặc thay đổi trong mối quan hệ.', 'Công ty có mức nợ vay cao với tổng nợ ngắn hạn và dài hạn khoảng 5.187 tỷ VNĐ, trong đó có khoản vay thế chấp bằng bất động sản. Chi phí lãi vay tăng mạnh, gây áp lực lên dòng tiền. Công ty đã có dòng tiền hoạt động kinh doanh âm trong năm, cho thấy rủi ro thanh toán. Tuy nhiên, các khoản vay có thời hạn dài và được đảm bảo bằng tài sản.', 'Hàng tồn kho và xây dựng dở dang có giá trị tương đối nhỏ so với tổng tài sản, do đó rủi ro tồn kho thấp. Tuy nhiên, xây dựng dở dang có thể liên quan đến dự án bất động sản, cần theo dõi tiến độ và khả năng chuyển đổi.', 6, 'Công ty Cổ phần Vincom Retail là đơn vị kinh doanh bất động sản hàng đầu với mạng lưới trung tâm thương mại lớn. Kết quả kinh doanh năm 2024 giảm do chi phí tăng, đặc biệt là chi phí tài chính. Nợ vay cao và dòng tiền âm là điểm đáng lo ngại, nhưng công ty có tài sản đảm bảo và mối quan hệ vững chắc với Tập đoàn Vingroup. Triển vọng phụ thuộc vào khả năng quản lý nợ và duy trì doanh thu từ cho thuê.'),
('VRE_2023_parent', 'VRE', 2023, 'parent', 'Công ty có mối quan hệ kinh doanh phức tạp và sâu rộng với Tập đoàn Vingroup – Công ty CP (công ty mẹ cấp cao nhất) và các công ty liên quan. Đáng lưu ý: (1) Khoản đặt cọc đầu tư lớn (7.893 tỷ VND) cho Tập đoàn Vingroup không có tài sản đảm bảo; (2) Khoản cho vay 1.190 tỷ VND cho Công ty con (Công ty TNHH Vận hành Vincom Retail) không có tài sản đảm bảo; (3) Giao dịch mua bán dịch vụ nội bộ diễn ra thường xuyên. Các giao dịch này có thể tiềm ẩn rủi ro về tính công bằng, minh bạch và nguy cơ chuyển giá trong tập đoàn.', 'Nợ vay ngắn hạn tăng mạnh từ 1.045 tỷ lên 2.962 tỷ VND (tăng 183%). Trong đó, khoản vay từ Deutsche Bank được thế chấp bằng tài sản của công ty con, nhưng khoản vay từ công ty con (Công ty TNHH Vận hành Vincom Retail) trị giá 1.190 tỷ VND không có tài sản đảm bảo và có lãi suất cố định cao (12%/năm). Áp lực trả nợ là đáng kể, đặc biệt khi các khoản vay ngân hàng có quyền yêu cầu trả nợ trước hạn từ tháng 9/2024.', 'Hàng tồn kho giảm mạnh từ 39.581 triệu xuống 8.785 triệu VND (giảm 78%), chủ yếu do bán hết bất động sản để bán. Không có hàng tồn kho dở dang (bất động sản đang xây dựng) tại cuối kỳ. Rủi ro tồn kho thấp.', 7, 'Công ty có kết quả kinh doanh tăng trưởng mạnh (Lợi nhuận sau thuế riêng tăng 69%, hợp nhất tăng 59%) nhờ giảm giá vốn và tăng doanh thu hoạt động tài chính. Tuy nhiên, tiềm ẩn rủi ro tài chính lớn: (1) Tăng trưởng nợ vay ngắn hạn đột biến; (2) Các khoản đặt cọc đầu tư khổng lồ cho công ty mẹ không có tài sản đảm bảo; (3) Cho vay nội bộ không có tài sản đảm bảo. Khả năng sinh lời tốt nhưng cấu trúc tài chính phụ thuộc lớn vào Tập đoàn mẹ và các công ty liên quan.'),
('VRE_2022_consolidated', 'VRE', 2022, 'consolidated', 'Doanh nghiệp có giao dịch lớn và phức tạp với các bên liên quan trong Tập đoàn Vingroup, bao gồm đặt cọc đầu tư lớn, cho vay, mua bán hàng hóa/dịch vụ. Việc cho vay lớn cho Công ty CP Sản xuất và Kinh doanh VinFast (8.165 tỷ đồng thu hồi trong năm) và đặt cọc đầu tư cho Tập đoàn Vingroup (2.293 tỷ đồng) cho thấy sự phụ thuộc và rủi ro tiềm ẩn từ các giao dịch nội bộ tập đoàn.', 'Áp lực nợ vay ở mức trung bình. Công ty có trái phiếu đáo hạn lớn vào năm 2023 (khoảng 1.045 tỷ đồng) và nợ thuê tài chính dài hạn. Tuy nhiên, tiền mặt và tương đương tiền đầu năm 2023 đạt 7.019 tỷ đồng, lớn hơn nhiều so với nợ ngắn hạn đến hạn. Lãi suất trái phiếu là thả nổi, gây rủi ro lãi suất.', 'Rủi ro tồn kho trung bình. Hàng tồn kho chủ yếu là bất động sản xây dựng dở dang (1.130 tỷ đồng) tăng mạnh so với đầu năm. Dự án dở dang lớn như Vincom Plaza Biên Hòa 2 (135 tỷ), Vincom Điện Biên (129 tỷ) cần theo dõi tiến độ và khả năng tiêu thụ.', 6, 'Doanh nghiệp hoạt động mạnh mẽ trong lĩnh vực cho thuê trung tâm thương mại, với doanh thu và lợi nhuận tăng trưởng tốt. Tình hình tài chính lành mạnh với lượng tiền mặt dồi dào. Tuy nhiên, rủi ro chính nằm ở các giao dịch lớn với bên liên quan trong tập đoàn, áp lực đáo hạn trái phiếu và tiến độ các dự án bất động sản dở dang.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VRE_2021_parent', 'VRE', 2021, 'parent', 'Công ty có hệ sinh thái giao dịch nội bộ phức tạp với Tập đoàn Vingroup (công ty mẹ) và các công ty liên quan. Đáng chú ý: (1) Các khoản đặt cọc đầu tư cho mục đích mua trung tâm thương mại lên đến 3.607.820 triệu VND (31/12/2021) không có tài sản đảm bảo; (2) Cho vay các công ty con và liên quan với lãi suất 8,1%-10%/năm; (3) Mua hàng hóa/dịch vụ từ công ty mẹ (209.514 triệu VND) và Vinhomes (151.360 triệu VND) theo giá thỏa thuận, không rõ cơ chế giá thị trường. Rủi ro xung đột lợi ích và chuyển giá trong nội bộ tập đoàn là đáng kể.', 'Nợ phải trả giảm mạnh từ 8.014.945 triệu VND xuống 4.704.097 triệu VND do trả nợ trái phiếu 2.600.000 triệu VND. Trái phiếu còn lại trị giá 2.965.992 triệu VND đáo hạn vào 2023-2025, được thế chấp bằng tài sản trung tâm thương mại của công ty con. Chi phí lãi vay thuần (454.165 triệu VND) chiếm tỷ trọng đáng kể, tuy nhiên Công ty có tiền mặt lớn (2.288.471 triệu VND) và dòng tiền kinh doanh dương (164.309 triệu VND). Áp lực trả nợ trái phiếu đáo hạn 2023-2025 là rủi ro cần theo dõi.', 'Hàng tồn kho giảm mạnh từ 503.342 triệu VND xuống 117.408 triệu VND (-77%), chủ yếu do bất động sản đang xây dựng giảm từ 422.004 triệu VND xuống 9.521 triệu VND, cho thấy tiến độ bàn giao dự án tốt. Chi phí xây dựng dở dang tăng nhẹ từ 647.219 triệu VND lên 667.777 triệu VND với 3 dự án lớn đang triển khai (Mỹ Tho, Bạc Liêu, Sông Công). Rủi ro tồn kho ở mức thấp, tuy nhiên cần theo dõi tiến độ hoàn thành các dự án dở dang trong bối cảnh thị trường bất động sản khó khăn.', 7, 'Vincom Retail chịu tác động nặng nề từ đại dịch COVID-19 với doanh thu thuần giảm 40% (riêng lẻ) và lợi nhuận sau thuế giảm 54% do phải miễn/giảm tiền thuê cho khách thuê bị ảnh hưởng. Hệ sinh thái giao dịch bên liên quan phức tạp với Tập đoàn Vingroup với các khoản đặt cọc đầu tư lớn không có tài sản đảm bảo (3.607 tỷ VND) là điểm rủi ro về quản trị. Công ty đã tích cực giảm nợ trái phiếu, duy trì vị thế tiền mặt tốt và có tài sản bất động sản đầu tư trị giá 4.628 tỷ VND làm nền tảng. Tuy nhiên, triển vọng phụ thuộc lớn vào sự phục hồi của hoạt động cho thuê trung tâm thương mại và khả năng quản lý dòng tiền để đáo hạn trái phiếu 2023-2025.'),
('VRE_2021_consolidated', 'VRE', 2021, 'consolidated', 'Công ty có nhiều giao dịch mua bán, đặt cọc đầu tư và cho vay với các bên liên quan trong Tập đoàn Vingroup. Các giao dịch này có thể không theo giá thị trường, tạo rủi ro về minh bạch và lợi ích nhóm. Đặc biệt, việc cho vay lớn với Công ty Cổ phần Vinpearl (1.250 tỷ VND) và Công ty TNHH Sản xuất và Kinh doanh VinFast (295 tỷ VND, lãi suất 10%) cần được giám sát chặt chẽ.', 'Công ty có nợ trái phiếu doanh nghiệp lớn (khoảng 2.966 tỷ VND) với lãi suất cao (9,5-10% năm đầu, sau thả nổi) và nợ thuê tài chính dài hạn (192 tỷ VND). Áp lực trả lãi và nợ gốc là đáng kể, đặc biệt trong bối cảnh lãi suất có thể tăng. Tài sản thế chấp chủ yếu là bất động sản đầu tư, bị ảnh hưởng bởi biến động thị trường.', 'Hàng tồn kho bất động sản (bao gồm bất động sản đang xây dựng dở dang và thành phẩm) chiếm hơn 582 tỷ VND. Dịch Covid-19 có thể gây chậm tiến độ thi công và giảm nhu cầu, dẫn đến nguy cơ ứ đọng vốn và giảm giá trị tồn kho.', 6, 'Công ty chịu tác động nặng nề từ đại dịch Covid-19, doanh thu và lợi nhuận giảm mạnh (lợi nhuận sau thuế giảm 45%). Dòng tiền từ hoạt động kinh doanh vẫn dương nhưng giảm so với năm trước. Nợ vay cao với lãi suất biến động là rủi ro chính. Công ty có hệ thống tài sản lớn (bất động sản đầu tư) và mối quan hệ chặt chẽ với Tập đoàn Vingroup, nhưng điều này cũng tiềm ẩn rủi ro giao dịch với bên liên quan. Triển vọng phụ thuộc vào sự phục hồi của thị trường bất động sản và du lịch.'),
('VRE_2022_parent', 'VRE', 2022, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt với Tập đoàn Vingroup, nhưng được thực hiện theo điều khoản kinh doanh thông thường. Rủi ro liên quan đến giao dịch bên liên quan ở mức trung bình.', 'Áp lực nợ vay thấp do tỷ lệ nợ trên vốn chủ sở hữu thấp và khả năng thanh toán tốt. Trái phiếu phát hành có lãi suất cao nhưng được đảm bảo bằng tài sản, giảm thiểu rủi ro.', 'Hàng tồn kho giảm mạnh từ 117,408 triệu VND xuống 39,581 triệu VND, cho thấy quản lý tồn kho hiệu quả hoặc giảm hoạt động bán bất động sản. Rủi ro tồn kho thấp.', 4, 'Công ty có tình hình tài chính lành mạnh với lợi nhuận tăng trưởng, dòng tiền hoạt động kinh doanh dương, và tỷ lệ nợ thấp. Triển vọng đầu tư tích cực trong dài hạn nhờ ngành bán lẻ phục hồi và mở rộng trung tâm thương mại.'),
('VRE_2020_parent', 'VRE', 2020, 'parent', 'Công ty có quan hệ mật thiết với Tập đoàn Vingroup (công ty mẹ) và nhiều công ty con/công ty liên quan trong hệ sinh thái Vingroup. Các giao dịch bao gồm: cho vay với lãi suất 10%/năm cho công ty con, đặt cọc đầu tư lớn cho các đối tác liên quan (tổng cộng hơn 4,200 tỷ VND đặt cọc cho mục đích đầu tư), mua bán dịch vụ qua lại. Tuy nhiên, các giao dịch này phục vụ mục đích kinh doanh chính (phát triển và vận hành trung tâm thương mại) và được thực hiện theo điều kiện thị trường. Rủi ro tập trung ở mức độ phụ thuộc vào hệ sinh thái Vingroup và các khoản đặt cọc đầu tư không có tài sản đảm bảo.', 'Nợ dài hạn chủ yếu là trái phiếu phát hành (5,537 tỷ VND) với lãi suất thả nổi từ 8.1%-10%/năm. Trái phiếu được thế chấp bằng bất động sản đầu tư (trung tâm thương mại) của các công ty con. Công ty có tỷ lệ nợ/vốn chủ sở hữu khoảng 32%, mức chấp nhận được. Tiền mặt và tương đương tiền đạt 2,259 tỷ VND cộng với đầu tư ngắn hạn 1,825 tỷ VND, đảm bảo khả năng thanh toán ngắn hạn. Tuy nhiên, áp lực lãi vay tăng (428 tỷ VND trong năm 2020) do phát hành thêm trái phiếu 3,050 tỷ VND.', 'Hàng tồn kho giảm mạnh từ 952 tỷ VND xuống 503 tỷ VND, cho thấy tiến độ bán hàng tích cực. Tuy nhiên, chi phí xây dựng cơ bản dở dang tăng từ 377 tỷ lên 647 tỷ VND với 3 dự án chính đang triển khai (Mỹ Tho, Sông Công, Bạc Liêu). Các dự án này cần được theo dõi tiến độ để tránh ứ đọng vốn. Bất động sản đầu tư tăng từ 4,269 tỷ lên 4,544 tỷ VND, phản ánh hoạt động đầu tư mở rộng trung tâm thương mại.', 5, 'Vincom Retail là công ty con của Tập đoàn Vingroup, hoạt động chính trong lĩnh vực đầu tư và vận hành trung tâm thương mại. Năm 2020, doanh thu và lợi nhuận giảm do ảnh hưởng của dịch Covid-19 (LNST giảm 76% từ 4,103 tỷ xuống 1,005 tỷ VND). Công ty có cơ cấu tài sản lớn (33,026 tỷ VND) với bất động sản đầu tư chiếm tỷ trọng cao. Điểm mạnh là hệ thống trung tâm thương mại lớn, dòng tiền hoạt động kinh doanh dương mạnh (1,443 tỷ VND). Điểm rủi ro là phụ thuộc vào hệ sinh thái Vingroup, nợ trái phiếu lớn với lãi suất thả nổi, và các khoản đặt cọc đầu tư không có tài sản đảm bảo. Công ty đang trong giai đoạn mở rộng với nhiều dự án dở dang, cần quản lý tốt tiến độ và dòng tiền.'),
('VRE_2020_consolidated', 'VRE', 2020, 'consolidated', 'Giao dịch với các bên liên quan, đặc biệt với công ty mẹ Tập đoàn Vingroup và các công ty con trong tập đoàn, diễn ra thường xuyên với giá trị lớn. Các giao dịch chủ yếu là mua bán hàng hóa dịch vụ và đặt cọc đầu tư, được thực hiện theo điều khoản kinh doanh thông thường. Tuy nhiên, sự phụ thuộc vào tập đoàn mẹ và các công ty liên quan có thể tạo rủi ro về tính độc lập và tính minh bạch.', 'Nợ vay bao gồm trái phiếu doanh nghiệp và nợ thuê tàiính với tổng giá trị lớn, phần lớn là nợ dài hạn. Lãi suất cao (8.1% đến 10% một năm) tạo áp lực chi phí tài chính. Công ty sử dụng tài sản bất động sản đầu tư làm đảm bảo, giảm rủi ro nhưng tăng cam kết tài sản. Khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh và cho thuê.', 'Hàng tồn kho chủ yếu là bất động sản xây dựng dở dang và thành phẩm. Các dự án xây dựng dở dang có giá trị cao và đang trong quá trình triển khai, rủi ro liên quan đến tiến độ xây dựng và khả năng tiêu thụ trên thị trường. Dịch Covid-19 ảnh hưởng đến doanh thu cho thuê, có thể tác động đến giá trị tồn kho.', 6, 'Vincom Retail là công ty hàng đầu trong lĩnh vực bán lẻ bất động sản tại Việt Nam, với danh mục trung tâm thương mại lớn. Năm 2020, lợi nhuận giảm 16% so với năm trước do ảnh hưởng của đại dịch Covid-19, đặc biệt doanh thu cho thuê giảm. Công ty có tỷ suất lợi nhuận gộp cao nhưng nợ vay tăng mạnh để tài trợ mở rộng. Quản trị công ty có rủi ro trung bình do giao dịch lớn với bên liên quan và cơ cấu nợ phức tạp. Triển vọng phụ thuộc vào phục hồi kinh tế và quản lý dự án.'),
('VRE_2019_parent', 'VRE', 2019, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt với Tập đoàn Vingroup – Công ty CP (công ty mẹ) và các công ty con, với các khoản đặt cọc đầu tư lớn, cho vay không lãi suất và mua bán dịch vụ. Điều này có thể gây rủi ro về giá giao dịch không công bằng và phụ thuộc vào các bên liên quan.', 'Công ty có trái phiếu dài hạn với lãi suất thả nổi, được thế chấp bằng tài sản bất động sản đầu tư. Áp lực nợ vay không quá cao do giảm chi phí lãi vay và thanh toán nợ gốc. Tuy nhiên, lãi suất trái phiếu có thể biến động và tài sản thế chấp là bất động sản có thể bị ảnh hưởng bởi thị trường.', 'Hàng tồn kho bất động sản tăng, chủ yếu là bất động sản đang xây dựng và đã hoàn thành. Dự phòng giảm giá chưa được trích lập, cho thấy không có rủi ro giảm giá đáng kể. Tuy nhiên, tồn kho dở dang lớn có thể bị ứ đọng nếu thị trường bất động sản suy giảm.', 6, 'Công ty có kết quả kinh doanh tăng trưởng mạnh, đặc biệt doanh thu cho thuê và lợi nhuận từ hoạt động tài chính. Tuy nhiên, quản trị doanh nghiệp có rủi ro trung bình do giao dịch bên liên quan phức tạp. Nợ vay được kiểm soát tốt với giảm chi phí lãi vay. Triển vọng đầu tư tích cực nhờ vào mạng lưới trung tâm thương mại mở rộng.'),
('VRE_2018_consolidated', 'VRE', 2018, 'consolidated', 'Doanh nghiệp có lượng giao dịch rất lớn và phức tạp với các bên liên quan, đặc biệt là Tập đoàn Vingroup (công ty mẹ) và các công ty thành viên như Vinhomes, Vincommerce. Các giao dịch bao gồm mua bán tài sản, hàng hóa dịch vụ, đặt cọc đầu tư với giá trị hàng nghìn tỷ đồng. Mối quan hệ kinh doanh mật thiết này có thể tiềm ẩn rủi ro về giá chuyển nhượng không theo giá thị trường và sự phụ thuộc vào hệ sinh thái Vingroup.', 'Công ty có khoản nợ trái phiếu lớn (gần 2.600 tỷ VND) với lãi suất thả nổi, tạo áp lực tài chính khi lãi suất biến động. Tuy nhiên, các khoản nợ này được đảm bảo bằng các bất động sản đầu tư chất lượng (trung tâm thương mại). Nợ thuê tài chính cũng chiếm tỷ trọng đáng kể. Công ty có dòng tiền hoạt động kinh doanh mạnh (hơn 3.500 tỷ năm 2018) giúp bù đắp áp lực trả nợ.', 'Hàng tồn kho chủ yếu là bất động sản để bán đang xây dựng dở dang (hơn 887 tỷ) và chi phí xây dựng cơ bản dở dang (hơn 1.300 tỷ). Phần lớn tồn kho này là các dự án bất động sản có thời gian xây dựng dài (12-36 tháng). Rủi ro tồn kho ứ đọng thấp do nhu cầu bất động sản và vị trí dự án tốt, song vẫn phụ thuộc vào biến động thị trường bất động sản.', 6, 'Vincom Retail là đơn vị chủ lực trong lĩnh vực cho thuê và kinh doanh trung tâm thương mại của Vingroup. Năm 2018, công ty ghi nhận kết quả kinh doanh tăng trưởng mạnh với doanh thu thuần tăng 65% và lợi nhuận sau thuế tăng 19%. Dòng tiền từ hoạt động kinh doanh rất mạnh. Tuy nhiên, công ty chịu rủi ro lớn từ sự phụ thuộc vào hệ sinh thái Vingroup (giao dịch bên liên quan lớn), áp lực nợ trái phiếu và tính chu kỳ của ngành bất động sản. Bộ máy quản trị có sự tham gia sâu của tập đoàn mẹ.'),
('VRE_2019_consolidated', 'VRE', 2019, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là Tập đoàn Vingroup (công ty mẹ) và các công ty con trong tập đoàn. Các giao dịch bao gồm mua bán hàng hóa dịch vụ, đặt cọc đầu tư, cho vay và nhận chuyển nhượng tài sản. Điều này tạo ra rủi ro phụ thuộc và có thể có xung đột lợi ích, nhưng giao dịch được thực hiện theo điều kiện thỏa thuận và kinh doanh thông thường.', 'Công ty có nợ vay dài hạn bao gồm trái phiếu và nợ thuê tài chính với tổng giá trị lớn. Tuy nhiên, công ty có dòng tiền hoạt động kinh doanh mạnh và tài sản đảm bảo, nên áp lực nợ vay ở mức kiểm soát được. Cần theo dõi lãi suất trái phiếu thả nổi có thể ảnh hưởng đến chi phí tài chính.', 'Hàng tồn kho bao gồm bất động sản xây dựng dở dang và thành phẩm bất động sản, với dự phòng giảm giá thấp. Rủi ro tồn kho liên quan đến tiến độ xây dựng và thị trường bất động sản, nhưng công ty có kinh nghiệm quản lý dự án.', 6, 'Công ty có sức khỏe tài chính tốt với doanh thu và lợi nhuận tăng trưởng mạnh, đặc biệt từ hoạt động cho thuê bất động sản đầu tư. Dòng tiền hoạt động kinh doanh dồi dào, hỗ trợ thanh toán nợ. Tuy nhiên, mối quan hệ mật thiết với Tập đoàn Vingroup tạo ra rủi ro phụ thuộc. Triển vọng đầu tư tích cực nhờ vào vị thế dẫn đầu trong lĩnh vực trung tâm thương mại tại Việt Nam.'),
('VRE_2017_consolidated', 'VRE', 2017, 'consolidated', 'Doanh nghiệp có mối quan hệ kinh doanh mật thiết với Tập đoàn Vingroup (công ty mẹ) và các công ty trong cùng Tập đoàn. Các giao dịch bao gồm cho vay không có tài sản đảm bảo với lãi suất cố định 13%/năm, mua bán hàng hóa/dịch vụ theo thỏa thuận, và hợp tác đầu tư. Mặc dù giá trị giao dịch lớn, không có bằng chứng rõ ràng về giao dịch bất thường như mua bán chênh lệch lớn hoặc cho vay không lãi suất. Tuy nhiên, sự tập trung giao dịch với bên liên quan tạo ra rủi ro phụ thuộc.', 'Áp lực nợ vay ở mức trung bình. Nợ vay chủ yếu là trái phiếu doanh nghiệp 3.000 tỷ VND với lãi suất thả nổi, có tài sản thế chấp bằng bất động sản đầu tư (các trung tâm thương mại). Nợ ngắn hạn tăng mạnh do trái phiếu đáo hạn. Công ty có đủ tài sản để đảm bảo, nhưng lãi suất thả nổi tạo rủi ro lãi suất.', 'Hàng tồn kho chủ yếu là bất động sản xây dựng dở dang (hơn 1.786 tỷ VND), có dự phòng giảm giá 26 tỷ VND. Dự án xây dựng dở dang trị giá 1.080 tỷ VND cho thấy hoạt động đầu tư phát triển mạnh, nhưng cũng tiềm ẩn rủi ro nếu thị trường bất động sản suy giảm.', 6, 'Công ty Cổ phần Vincom Retail có nền tảng tài chính vững mạnh với tỷ suất lợi nhuận gộp cao (50.7%), hoạt động kinh doanh cho thuê bất động sản đầu tư là nguồn doanh thu chính. Tuy nhiên, doanh nghiệp phụ thuộc lớn vào Tập đoàn Vingroup và các công ty con trong Tập đoàn. Nợ vay ở mức kiểm soát được với tài sản thế chấp đảm bảo. Hàng tồn kho và dự án dở dang lớn cho thấy chiến lược phát triển mở rộng, nhưng cần theo dõi rủi ro thị trường. Điểm rủi ro quản trị trung bình (6/10) do nhiều giao dịch bên liên quan phức tạp.'),
('VRE_2017_parent', 'VRE', 2017, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan trong Tập đoàn Vingroup với giá trị lớn (cho vay, mua bán dịch vụ, đặt cọc hợp tác đầu tư). Các giao dịch được thực hiện theo giá thỏa thuận và không có dự phòng phải thu khó đòi, nhưng tính chất tập trung vào tập đoàn mẹ tạo rủi ro phụ thuộc.', 'Nợ vay chủ yếu là trái phiếu doanh nghiệp với tổng giá trị lớn (gần 5.800 tỷ VNĐ), trong đó nợ ngắn hạn đến hạn trả là 2.798 tỷ VNĐ. Công ty có tiền mặt và các khoản đầu tư nắm giữ đến đáo hạn, nhưng áp lực trả nợ trái phiếu đáo hạn là đáng kể.', 'Hàng tồn kho chủ yếu là bất động sản để bán và đang xây dựng, với giá trị tăng so với đầu năm. Rủi ro tồn kho phụ thuộc vào tiến độ triển khai dự án và tình hình thị trường bất động sản.', 6, 'Công ty có kết quả kinh doanh tích cực với lợi nhuận sau thuế tăng mạnh. Tuy nhiên, doanh thu và lợi nhuận phụ thuộc lớn vào hoạt động cho thuê và chuyển nhượng bất động sản trong Tập đoàn Vingroup. Nợ vay ở mức cao, đặc biệt là trái phiếu đáo hạn, cần theo dõi khả năng tái cơ cấu nợ. Công ty có nhiều giao dịch với bên liên quan nhưng được kiểm soát thông qua các thỏa thuận và cam kết.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VRE_2016_parent', 'VRE', 2016, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp với Tập đoàn Vingroup (công ty mẹ), Warburg Pincus và Credit Suisse (cổ đông ưu đãi), cùng nhiều công ty con và công ty trong cùng Tập đoàn. Công ty cho vay nội bộ lớn (hơn 7.600 tỷ VND ngắn hạn) cho các công ty con không có tài sản đảm bảo với lãi suất 11%-11.5%/năm. Các khoản vay từ Vingroup, Warburg Pincus, Credit Suisse cũng không có tài sản đảm bảo. Tuy nhiên, lãi suất cho vay và đi vay phản ánh điều kiện thị trường, không có dấu hiệu bất thường rõ ràng. Các giao dịch mua bán hàng hóa/dịch vụ theo giá niêm yết thông thường. Công ty thực hiện nhiều giao dịch sáp nhập, thoái vốn công ty con trong năm (bán Ngôi Sao Xanh, Metropolis, Riverview Đà Nẵng), cho thấy hoạt động tái cơ cấu liên tục trong hệ sinh thái Vingroup.', 'Tổng nợ phải trả giảm mạnh từ 16.063 tỷ xuống còn 5.092 tỷ VND (giảm 68%), phản ánh việc tất toán trước hạn khoản vay lớn từ Vingroup. Nợ vay dài hạn giảm từ 12.146 tỷ xuống còn 4.312 tỷ VND. Tuy nhiên, Công ty vẫn gánh chịu chi phí bồi thường 140,6 tỷ VND do tất toán trước hạn. Trái phiếu doanh nghiệp 2.800 tỷ VND đáo hạn trong 3 năm được thế chấp bằng bất động sản đầu tư. Các khoản vay chuyển đổi từ Warburg Pincus và Credit Suisse (tổng 455,8 tỷ VND) đáo hạn tháng 1/2019, tiềm ẩn rủi ro chuyển đổi hoặc đáo hạn. Vốn chủ sở hữu tăng mạnh lên 22.178 tỷ VND nhờ phát hành thêm cổ phiếu, giúp tỷ lệ nợ/vốn chủ sở hữu giảm xuống mức an toàn khoảng 23%.', 'Hàng tồn kho giảm mạnh từ 1.394 tỷ xuống 318 tỷ VND. Hàng tồn kho chủ yếu là bất động sản để bán (hoàn thành 104 tỷ, đang xây dựng 214 tỷ). Chi phí xây dựng cơ bản dở dang tăng từ 42 tỷ lên 373 tỷ VND, tập trung vào 3 dự án Vincom Plaza (Hậu Giang, Trà Vinh, Vĩnh Long) - đây là các dự án trung tâm thương mại mới. Dự án SAP đã hoàn thành (không còn trong dở dang). Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho ở mức trung bình do đa số là bất động sản để bán đã hoàn thành hoặc gần hoàn thành.', 5, 'Vincom Retail là công ty con của Tập đoàn Vingroup, hoạt động chính trong lĩnh vực đầu tư và phát triển trung tâm thương mại cho thuê. Năm 2016, công ty đạt lợi nhuận sau thuế 838 tỷ VND (tăng 157% so với năm trước), biên lợi nhuận gộp 19,2%. Công ty đã thực hiện IPO thành công và huy động được hơn 6.900 tỷ VND vốn mới, nâng vốn chủ sở hữu lên 22.178 tỷ VND. Đáng chú ý, công ty đã tất toán phần lớn nợ vay từ Vingroup (từ 8.909 tỷ xuống 1.063 tỷ), giảm đáng kể rủi ro tài chính. Tuy nhiên, công ty vẫn phụ thuộc lớn vào hệ sinh thái Vingroup trong hoạt động kinh doanh và tài trợ, với các khoản vay nội bộ và giao dịch mua bán dịch vụ xây dựng với công ty trong Tập đoàn. Đánh giá tổng thể: triển vọng tích cực nhờ vị thế dẫn đầu thị trường bán lẻ, tuy nhiên vẫn cần theo dõi rủi ro tập trung vào hệ sinh thái Vingroup.'),
('VRE_2016_consolidated', 'VRE', 2016, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan trong Tập đoàn Vingroup: cho vay dài hạn 2.613,6 tỷ VND cho công ty mẹ với lãi suất 13%/năm; mua dịch vụ xây dựng từ Công ty Xây dựng Vincom 1 (1.120 tỷ VND); vay chuyển đổi từ Warburg Pincus và Credit Suisse với lãi suất 8,75%/năm không có tài sản đảm bảo. Các giao dịch này tuân theo giá thị trường và không có dự phòng phải thu khó đòi, nhưng mức độ liên kết chặt chẽ với Tập đoàn tạo rủi ro tập trung.', 'Tổng nợ phải trả 9.615 tỷ VND với nợ vay chiếm tỷ trọng lớn: trái phiếu 2.792 tỷ VND đáo hạn tháng 6/2018; vay từ Vingroup 2.663 tỷ VND đáo hạn 2018-2019; vay chuyển đổi 455,8 tỷ VND đáo hạn tháng 1/2019. Chi phí lãi vay 1.252 tỷ VND/năm. Nhiều khoản vay không có tài sản đảm bảo. Áp lực trả nợ gốc và lãi vay đã trả năm 2016 là 1.807 tỷ VND. Công ty có tài sản thế chấp là bất động sản đầu tư và TSCĐ.', 'Hàng tồn kho giảm mạnh từ 1.483 tỷ xuống 682 tỷ VND do thanh lý BĐS. Chi phí xây dựng cơ bản dở dang giảm từ 6.365 tỷ xuống 1.469 tỷ VND cho thấy tiến độ triển khai dự án tốt. Tuy nhiên, nhiều dự án lớn vẫn đang triển khai (Vinhomes Star 423 tỷ, Vincom Bắc Ninh 292 tỷ, Vincom Plaza Trà Vinh 139 tỷ) đòi hỏi vốn đầu tư tiếp tục.', 7, 'Vincom Retail đạt kết quả kinh doanh ấn tượng với lợi nhuận sau thuế tăng 124% (2.439 tỷ VND năm 2016 vs 1.089 tỷ VND năm 2015), doanh thu cho thuê BĐS tăng mạnh 56,7%. Công ty có hệ thống TTTM lớn với giá trị thị trường 28.317 tỷ VND. Đã huy động thêm 6.919 tỷ VND vốn cổ phần, cải thiện cơ cấu vốn. Tuy nhiên, rủi ro đến từ: (1) Giao dịch bên liên quan phức tạp với Tập đoàn; (2) Nợ vay lớn đáo hạn 2018-2019; (3) Nhiều dự án xây dựng dở dang cần vốn tiếp. Công ty có tiềm năng tăng trưởng từ mảng cho thuê BĐS thương mại nhưng cần quản lý tốt dòng tiền và cơ cấu nợ.'),
('VRC_2025_consolidated', 'VRC', 2025, 'consolidated', 'Doanh nghiệp có nhiều giao dịch phức tạp với bên liên quan, đặc biệt với cổ đông lớn và Tổng Giám đốc Trần Thị Vân: cho vay không có tài sản đảm bảo với lãi suất thấp (0.2%/năm), mua bán bất động sản với giá thỏa thuận với nhân viên và người liên quan, nhận chuyển nhượng lại đất đã bán trước đó. Điều này đặt ra rủi ro về xung đột lợi ích và khả năng thao túng giá.', 'Nợ vay ngắn hạn chủ yếu từ cổ đông lớn (331.9 tỷ VND) với lãi suất rất thấp (0.2%/năm) và không có tài sản đảm bảo, tạo áp lực thanh toán thấp nhưng liên quan đến giao dịch với bên liên quan. Có khoản tiền thuê đất phải nộp 3.387 tỷ VND theo kết luận thanh tra, tiềm ẩn nghĩa vụ nợ tiềm tàng.', 'Hàng tồn kho là các dự án bất động sản dở dang với tổng giá trị 1.199 tỷ VND, không có dự phòng giảm giá. Có giao dịch nhận chuyển nhượng lại đất đã bán cho nhân viên năm 2024 với giá bằng giá bán, đặt câu hỏi về tính thanh khoản và giá trị thực của các dự án.', 8, 'Doanh nghiệp có quy mô nhỏ, lợi nhuận sau thuế giảm mạnh 91.96% so với năm trước (từ 13.023 tỷ xuống 1.177 tỷ VND) do không có thu nhập bất thường từ bồi thường đất. Áp lực nợ vay thấp nhưng rủi ro quản trị cao với nhiều giao dịch phức tạp với bên liên quan, thay đổi ban lãnh đạo频繁, và các vấn đề pháp lý chưa được giải quyết (tiền thuê đất, tranh chấp trọng tài). Điểm sáng là dòng tiền hoạt động kinh doanh cải thiện và tỷ lệ lợi nhuận gộp cao (83%). Triển vọng đầu tư không rõ ràng do phụ thuộc vào việc xử lý các rủi ro pháp lý và thanh khoản bất động sản.'),
('VRE_2015_parent', 'VRE', 2015, 'parent', 'Công ty có giao dịch rất lớn và phức tạp với bên liên quan, đặc biệt là Tập đoàn Vingroup (công ty mẹ) và các công ty con. Các giao dịch bao gồm cho vay không tài sản đảm bảo với lãi suất từ 7% đến 13%, đồng thời đi vay từ công ty mẹ với lãi suất cao (lên đến 16.47%/năm). Điều này đặt ra rủi ro về giao dịch không minh bạch, tiềm ẩn xung đột lợi ích và ảnh hưởng đến lợi ích của cổ đông thiểu số.', 'Tỷ lệ nợ phải trả trên tổng nguồn vốn chiếm hơn 53% (16.063 tỷ / 29.872 tỷ). Nợ vay chủ yếu đến từ Tập đoàn Vingroup với lãi suất cao, tạo áp lực trả nợ và chi phí tài chính lớn (chi phí lãi vay hơn 1.081 tỷ trong năm). Công ty có phát hành trái phiếu doanh nghiệp 2.800 tỷ có tài sản thế chấp. Áp lực nợ vay đáng kể, đặc biệt trong bối cảnh Công ty đang lỗ lũy kế.', 'Hàng tồn kho lớn (gần 1.400 tỷ) là dự án Vinhomes Nguyễn Chí Thanh. Chi phí xây dựng dở dang giảm so với đầu năm, cho thấy dự án có tiến độ. Tuy nhiên, bất động sản đầu tư có giá trị lớn, khấu hao hàng năm, cần đảm bảo công suất khai thác.', 7, 'Công ty tăng trưởng mạnh về doanh thu (gấp 28 lần năm trước) và có lợi nhuận sau thuế 325,6 tỷ. Tuy nhiên, công ty còn lỗ lũy kế 461 tỷ. Nợ vay lớn với lãi suất cao từ công ty mẹ và cổ đông nước ngoài gây áp lực tài chính. Công ty đang trong giai đoạn mở rộng nhanh qua mua sáp nhập nhiều công ty con, tiềm ẩn rủi ro tích hợp và quản trị. Điểm mạnh là hệ thống trung tâm thương mại lớn và kết nối với Tập đoàn Vingroup. Triển vọng phụ thuộc vào khả năng cải thiện lợi nhuận, giảm nợ và quản lý hiệu quả danh mục bất động sản.'),
('VRE_2015_consolidated', 'VRE', 2015, 'consolidated', 'Doanh nghiệp có giao dịch rất phức tạp và lớn với các bên liên quan thuộc Tập đoàn Vingroup. Các giao dịch bao gồm: vay mượn qua lại với lãi suất cao (7%-16,47%/năm) từ công ty mẹ, cho vay dài hạn với lãi suất 13%/năm cho công ty mẹ, trả trước xây dựng lớn (441 tỷ VND) cho Công ty Quản lý Xây dựng Vincom 1, đặt cọc đầu tư 553 tỷ VND cho công ty mẹ, và nhiều giao dịch mua bán dịch vụ với các công ty trong Tập đoàn. Mặc dù các giao dịch này được giải thích là trong quá trình kinh doanh bình thường, nhưng quy mô lớn và phức tạp đòi hỏi sự giám sát chặt chẽ để đảm bảo tính công bằng và minh bạch. Không có trích lập dự phòng phải thu khó đòi cho các khoản phải thu từ bên liên quan.', 'Tổng nợ phải trả là 21.025 tỷ VND (trong đó nợ ngắn hạn 6.215 tỷ, nợ dài hạn 14.810 tỷ) so với tổng tài sản 35.909 tỷ VND, tỷ lệ nợ trên tổng tài sản khoảng 58,6%. Công ty phụ thuộc lớn vào nguồn vốn vay từ công ty mẹ Tập đoàn Vingroup (hơn 10.500 tỷ VND dài hạn) với lãi suất cao. Trái phiếu doanh nghiệp 2.788 tỷ VND có tài sản thế chấp là bất động sản tại Vincom Bà Triệu. Chi phí lãi vay trong năm là 1.221 tỷ VND, áp lực trả nợ đáng kể. Tuy nhiên, công ty có bất động sản đầu tư giá trị lớn (15.319 tỷ VND) làm tài sản đảm bảo và dòng tiền từ hoạt động cho thuê ổn định.', 'Hàng tồn kho 1.483 tỷ VND chủ yếu là bất động sản để bán đang xây dựng (1.452 tỷ VND) tập trung vào dự án Vinhomes Nguyễn Chí Thanh và Vincom Hải Phòng. Các dự án xây dựng dở dang dài hạn lên tới 6.365 tỷ VND bao gồm nhiều dự án lớn như Vinhomes Star (3.014 tỷ), Vincom Center Thảo Điền (1.512 tỷ), Vincom Trung Tự (548 tỷ). Rủi ro chính là phụ thuộc vào khả năng tiêu thụ bất động sản và tiến độ xây dựng. Công ty không trích lập dự phòng giảm giá hàng tồn kho.', 7, 'Vincom Retail là doanh nghiệp kinh doanh bất động sản bán lẻ có quy mô lớn, thuộc hệ sinh thái Vingroup. Doanh thu đạt 5.958 tỷ VND (tăng 209% so với năm trước), lợi nhuận gộp 2.006 tỷ VND với biên gộp 33,7%. Công ty đang trong giai đoạn mở rộng mạnh mẽ với nhiều dự án mới và mua bán sáp nhập công ty con. Tuy nhiên, doanh nghiệp có rủi ro cao do: (1) nợ vay lớn và phụ thuộc vào vốn vay từ công ty mẹ; (2) giao dịch bên liên quan phức tạp, chồng chéo; (3) nhiều khoản đặt cọc đầu tư lớn cho các dự án tiềm năng; (4) chi phí lãi vay cao 1.221 tỷ VND. Điểm tích cực là bất động sản đầu tư (trung tâm thương mại) mang lại dòng tiền thuê ổn định và giá trị thị trường vượt xa giá trị sổ sách theo báo cáo định giá độc lập.'),
('VRC_2025_parent', 'VRC', 2025, 'parent', 'Công ty có giao dịch lớn với bên liên quan: cho vay công ty con ADEC với lãi suất 3%/năm (thấp hơn thị trường), cung cấp dịch vụ tư vấn cho công ty liên kết Mỹ Xuân với doanh thu 3.6 tỷ/năm. Giao dịch tập trung vào hai bên liên quan chính, tạo rủi ro phụ thuộc và có thể có giá chuyển nhượng không theo giá thị trường. Nghị quyết Đại hội đồng cổ đông đã thông qua chuyển nhượng cổ phần tại hai công ty này nhưng chưa thực hiện được.', 'Nợ vay ngắn hạn đã được trả hết cuối năm 2025. Tuy nhiên, Công ty có nghĩa vụ nợ tiềm tàng lớn: tiền thuê đất phải nộp theo Kết luận Thanh tra số 261 là 3.387 tỷ VND (đã nộp 2.3 tỷ, còn nợ 3.387 tỷ). Đây là khoản nợ liên quan đến tranh chấp đất đai từ thời cổ phần hóa, tạo áp lực tài chính đáng kể.', 'Công ty không có hàng tồn kho, dự án xây dựng dở dang hay bất động sản đầu tư. Hoạt động kinh doanh chính là dịch vụ tư vấn, không có rủi ro tồn kho.', 6, 'Công ty có biên lợi nhuận gộp rất cao (91.4%) nhưng doanh thu chủ yếu 3.6 tỷ/năm từ dịch vụ tư vấn cho công ty liên kết, tạo rủi do phụ thuộc. Tài sản chủ yếu là đầu tư vào công ty con và liên kết (971 tỷ). Năm 2025 lợi nhuận giảm 91.4% so với năm 2024 do năm trước có khoản thu nhập bồi thường đất lớn. Công ty có nghĩa vụ nợ tiềm tàng lớn về tiền thuê đất (3.387 tỷ) và đã bị phong tỏa tài khoản ngân hàng. Tình hình tài chính ổn định nhưng phụ thuộc lớn vào giao dịch bên liên quan và có tranh chấp đất đai kéo dài.'),
('VRC_2024_parent', 'VRC', 2024, 'parent', 'Công ty có các giao dịch với công ty con và công ty liên kết, bao gồm cho vay và cung cấp dịch vụ. Các giao dịch này được thực hiện theo giá thỏa thuận và có lãi suất. Tuy nhiên, có một số khoản phải thu từ các bên liên quan đã quá hạn và được trích lập dự phòng.', 'Áp lực nợ vay thấp, chỉ có nợ ngắn hạn từ công ty con với lãi suất 3%/năm. Không có nợ dài hạn.', 'Công ty không có hàng tồn kho và không có dự án xây dựng dở dang, do đó rủi ro tồn kho không đáng kể.', 4, 'Công ty có lợi nhuận sau thuế tăng trưởng 28.52%, tỷ suất lợi nhuận gộp cao (92.9%). Tuy nhiên, công ty có khoản nợ tiềm tàng về tiền thuê đất (16.4 tỷ VND) đang khiếu nại và nhiều khoản phải thu quá hạn. Đầu tư vào công ty con và liên kết chiếm tỷ trọng lớn trong tài sản. Nợ vay thấp, thanh khoản tốt.'),
('VRC_2023_parent', 'VRC', 2023, 'parent', 'Công ty có các giao dịch với công ty con (Adec) và công ty liên kết (Đóng tàu và Dịch vụ Cảng Mỹ Xuân). Các giao dịch bao gồm cho vay, cung cấp dịch vụ tư vấn và thu lãi cho vay. Giá dịch vụ là giá thỏa thuận. Các khoản công nợ phải thu từ các bên liên quan không có bảo đảm và được thanh toán bằng tiền. Không có dự phòng phải thu khó đòi cho các khoản nợ này.', 'Công ty không có nợ vay và nợ thuê tài chính dài hạn hoặc ngắn hạn trên Bảng cân đối kế toán. Các khoản nợ phải trả chủ yếu là phải trả người bán, chi phí phải trả (bao gồm tiền thuê đất tranh chấp) và thuế phải nộp. Công ty có khoản tiền thuê đất tranh chấp với Thanh tra tỉnh Bà Rịa - Vũng Tàu là 16.417.644.006 VND cho giai đoạn trước cổ phần hóa và 20.382.263.624 VND cho giai đoạn 2006-2013, chưa được ghi nhận là nợ phải trả. Đây là một nghĩa vụ nợ tiềm tàng lớn.', 'Công ty không có hàng tồn kho.', 3, 'Công ty có cơ cấu tài sản chủ yếu là các khoản đầu tư dài hạn vào công ty con và công ty liên kết, chiếm hơn 99% tổng tài sản. Nguồn thu nhập chính đến từ hoạt động cung cấp dịch vụ tư vấn cho công ty liên kết. Lợi nhuận sau thuế năm 2023 giảm mạnh (94,5%) so với năm 2022 do năm trước có khoản thu nhập lớn từ tiền bồi thường đất. Dòng tiền từ hoạt động kinh doanh âm liên tục. Rủi ro tài chính chính đến từ tranh chấp tiềm tàng về tiền thuê đất và sự tập trung nguồn thu vào các bên liên quan. Công ty không có nợ vay, nhưng gánh nặng tiềm tàng từ nghĩa vụ thuế đất là đáng kể.'),
('VRC_2024_consolidated', 'VRC', 2024, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm cho vay không lãi suất (hoặc lãi suất thấp 2,5-3%/năm) cho công ty liên kết và cá nhân liên quan, mua bán bất động sản với giá trị lớn với thành viên quản lý chủ chốt. Các giao dịch này có thể không được thực hiện trên cơ sở thị trường, tiềm ẩn rủi ro xung đột lợi ích và ảnh hưởng đến lợi ích cổ đông thiểu số.', 'Áp lực nợ vay ngắn hạn cao với khoản vay lớn từ Bà Trần Thị Vân (324.640.567.288 VND, lãi suất thấp 2,5%/năm) nhưng không có tài sản đảm bảo. Công ty cũng có nợ dài hạn 100.020.000.000 VND là tiền nhận ký quỹ kinh doanh. Khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh bất động sản, tuy nhiên tiền gửi ngân hàng bị phong tỏa (9.842.195.382 VND) làm giảm thanh khoản tức thời.', 'Hàng tồn kho chủ yếu là các dự án bất động sản dở dang với giá trị lớn (hơn 1.185 tỷ VND), không trích lập dự phòng giảm giá. Các dự án này có thể bị ứ đọng nếu thị trường bất động sản suy thoái, dẫn đến nguy cơ giá trị thuần có thể thực hiện được thấp hơn giá gốc.', 7, 'Công ty ghi nhận lợi nhuận tăng trưởng mạnh (lợi nhuận sau thuế tăng 339% so với năm trước) nhờ hoạt động kinh doanh bất động sản. Tuy nhiên, sức khỏe tài chính tiềm ẩn rủi ro: phụ thuộc lớn vào giao dịch bên liên quan, cơ cấu nợ ngắn hạn cao, và hàng tồn kho dở dang giá trị lớn. Ban lãnh đạo có sự biến động mạnh, với nhiều thay đổi trong Hội đồng quản trị và Ban Tổng Giám đốc. Triển vọng đầu tư phụ thuộc vào khả năng giải quyết tranh chấp đất đai (nợ tiềm tàng) và thanh khoản từ dự án bất động sản.'),
('VRC_2022_consolidated', 'VRC', 2022, 'consolidated', 'Công ty có giao dịch vay không lãi suất với cá nhân liên quan đến ban lãnh đạo và cung cấp dịch vụ cho công ty liên kết. Giá dịch vụ là giá thỏa thuận, không có dấu hiệu bất thường rõ ràng.', 'Nợ ngắn hạn tăng mạnh chủ yếu do trái phiếu đáo hạn, nhưng công ty có tài sản thế chấp và dòng tiền từ hoạt động kinh doanh dương.', 'Hàng tồn kho là các dự án bất động sản có giá trị lớn, không có dự phòng giảm giá, rủi ro ứ đọng nếu thị trường suy giảm.', 5, 'Lợi nhuận tăng vọt do thu nhập từ bồi thường đất, hoạt động kinh doanh cốt lõi còn yếu. Cơ cấu tài sản lớn nhưng nợ vay cao, cần theo dõi thanh khoản.');
PRAGMA foreign_keys = ON;
